 20вҶ’#include "pj_bridge/bridge_server.hpp"
 21вҶ’
 22вҶ’#include <spdlog/spdlog.h>
 23вҶ’
 24вҶ’#include <map>
 25вҶ’#include <nlohmann/json.hpp>
 26вҶ’#include <unordered_set>
 27вҶ’
 28вҶ’#include "pj_bridge/message_serializer.hpp"
 29вҶ’#include "pj_bridge/protocol_constants.hpp"
 30вҶ’
 31вҶ’using json = nlohmann::json;
 32вҶ’
 33вҶ’namespace pj_bridge {
 34вҶ’
 35вҶ’BridgeServer::BridgeServer(
 36вҶ’    std::shared_ptr<TopicSourceInterface> topic_source,
 37вҶ’    std::shared_ptr<SubscriptionManagerInterface> subscription_manager,
 38вҶ’    std::shared_ptr<MiddlewareInterface> middleware, int port, double session_timeout, double publish_rate)
 39вҶ’    : topic_source_(std::move(topic_source)),
 40вҶ’      subscription_manager_(std::move(subscription_manager)),
 41вҶ’      middleware_(std::move(middleware)),
 42вҶ’      port_(port),
 43вҶ’      session_timeout_(session_timeout),
 44вҶ’      publish_rate_(publish_rate),
 45вҶ’      initialized_(false),
 46вҶ’      total_messages_published_(0),
 47вҶ’      total_bytes_published_(0),
 48вҶ’      publish_cycles_(0) {}
 49вҶ’
 50вҶ’BridgeServer::~BridgeServer() {
 51вҶ’  // Shut down the middleware before members are destroyed so that
 52вҶ’  // disconnect callbacks (which capture `this`) cannot fire into
 53вҶ’  // a partially destroyed BridgeServer.
 54вҶ’  if (middleware_) {
 55вҶ’    middleware_->shutdown();
 56вҶ’  }
 57вҶ’}
 58вҶ’
 59вҶ’bool BridgeServer::initialize() {
 60вҶ’  if (initialized_) {
 61вҶ’    spdlog::warn("Bridge server already initialized");
 62вҶ’    return true;
 63вҶ’  }
 64вҶ’
 65вҶ’  spdlog::info("Initializing bridge server...");
 66вҶ’
 67вҶ’  message_buffer_ = std::make_shared<MessageBuffer>();
 68вҶ’  session_manager_ = std::make_unique<SessionManager>(session_timeout_);
 69вҶ’
 70вҶ’  spdlog::info("Core components created");
 71вҶ’
 72вҶ’  // Set the global message callback to feed into message buffer
 73вҶ’  subscription_manager_->set_message_callback(
 74вҶ’      [this](const std::string& topic_name, std::shared_ptr<std::vector<std::byte>> cdr_data, uint64_t timestamp_ns) {
 75вҶ’        {
 76вҶ’          std::lock_guard<std::mutex> lock(stats_mutex_);
 77вҶ’          topic_receive_counts_[topic_name]++;
 78вҶ’        }
 79вҶ’        if (message_buffer_) {
 80вҶ’          message_buffer_->add_message(topic_name, timestamp_ns, std::move(cdr_data));
 81вҶ’        }
 82вҶ’      });
 83вҶ’
 84вҶ’  // Register disconnect callback before middleware init to avoid missing events
 85вҶ’  middleware_->set_on_disconnect([this](const std::string& client_id) {
 86вҶ’    spdlog::info("Client disconnected: '{}'", client_id);
 87вҶ’    cleanup_session(client_id);
 88вҶ’  });
 89вҶ’
 90вҶ’  // Initialize middleware (may start accepting connections immediately)
 91вҶ’  auto result = middleware_->initialize(static_cast<uint16_t>(port_));
 92вҶ’  if (!result) {
 93вҶ’    spdlog::error("Failed to initialize middleware: {}", result.error());
 94вҶ’    return false;
 95вҶ’  }
 96вҶ’  spdlog::info("Middleware initialized (port: {})", port_);
 97вҶ’
 98вҶ’  if (publish_rate_ <= 0.0) {
 99вҶ’    spdlog::error("Invalid publish_rate: {:.1f} (must be > 0)", publish_rate_);
100вҶ’    return false;
101вҶ’  }
102вҶ’
103вҶ’  initialized_ = true;
104вҶ’  spdlog::info("Bridge server initialization complete");
105вҶ’
106вҶ’  return true;
107вҶ’}
108вҶ’
109вҶ’bool BridgeServer::process_requests() {
110вҶ’  if (!initialized_) {
111вҶ’    spdlog::error("Bridge server not initialized");
112вҶ’    return false;
113вҶ’  }
114вҶ’
115вҶ’  // Receive request (non-blocking with timeout)
116вҶ’  std::vector<uint8_t> request_data;
117вҶ’  std::string client_id;
118вҶ’  bool received = middleware_->receive_request(request_data, client_id);
119вҶ’
120вҶ’  if (!received || request_data.empty()) {
121вҶ’    return false;
122вҶ’  }
123вҶ’
124вҶ’  std::string request(request_data.begin(), request_data.end());
125вҶ’  if (client_id.empty()) {
126вҶ’    spdlog::warn("Received request with no client identity");
127вҶ’    return true;
128вҶ’  }
129вҶ’
130вҶ’  // Parse request JSON
131вҶ’  std::string response;
132вҶ’  json request_json;
133вҶ’  try {
134вҶ’    request_json = json::parse(request);
135вҶ’
136вҶ’    if (!request_json.contains("command")) {
137вҶ’      response = create_error_response("INVALID_REQUEST", "Missing 'command' field", request_json);
138вҶ’    } else {
139вҶ’      std::string command = request_json["command"];
140вҶ’
141вҶ’      spdlog::debug("Processing '{}' command from client '{}'", command, client_id);
142вҶ’
143вҶ’      if (command == "get_topics") {
144вҶ’        response = handle_get_topics(client_id, request_json);
145вҶ’      } else if (command == "subscribe") {
146вҶ’        response = handle_subscribe(client_id, request_json);
147вҶ’      } else if (command == "unsubscribe") {
148вҶ’        response = handle_unsubscribe(client_id, request_json);
149вҶ’      } else if (command == "heartbeat") {
150вҶ’        response = handle_heartbeat(client_id, request_json);
151вҶ’      } else if (command == "pause") {
152вҶ’        response = handle_pause(client_id, request_json);
153вҶ’      } else if (command == "resume") {
154вҶ’        response = handle_resume(client_id, request_json);
155вҶ’      } else {
156вҶ’        response = create_error_response("UNKNOWN_COMMAND", "Unknown command: " + command, request_json);
157вҶ’      }
158вҶ’    }
159вҶ’  } catch (const json::exception& e) {
160вҶ’    spdlog::error("JSON parse error: {}", e.what());
161вҶ’    response = create_error_response("INVALID_JSON", "Failed to parse JSON request", json::object());
162вҶ’  } catch (const std::exception& e) {
163вҶ’    spdlog::error("Error processing request: {}", e.what());
164вҶ’    response = create_error_response("INTERNAL_ERROR", "Internal server error", request_json);
165вҶ’  }
166вҶ’
167вҶ’  // Send response to the specific client
168вҶ’  std::vector<uint8_t> response_data(response.begin(), response.end());
169вҶ’  if (!middleware_->send_reply(client_id, response_data)) {
170вҶ’    spdlog::warn("Failed to send response to client '{}', cleaning up session", client_id);
171вҶ’    cleanup_session(client_id);
172вҶ’  }
173вҶ’  return true;
174вҶ’}
175вҶ’
176вҶ’std::string BridgeServer::handle_get_topics(const std::string& client_id, const nlohmann::json& request) {
177вҶ’  if (!session_manager_->session_exists(client_id)) {
178вҶ’    session_manager_->create_session(client_id);
179вҶ’    spdlog::info("Created new session for client '{}'", client_id);
180вҶ’  }
181вҶ’
182вҶ’  session_manager_->update_heartbeat(client_id);
