 33вҶ’void AggregatedMessageSerializer::serialize_message(
 34вҶ’    const std::string &topic_name, uint64_t timestamp_ns, const std::byte *data, size_t data_size) {
 35вҶ’  message_count_++;
 36вҶ’  write_str(serialized_data_, topic_name);
 37вҶ’
 38вҶ’  // Timestamp (uint64_t) - receive time
 39вҶ’  write_le(serialized_data_, timestamp_ns);
 40вҶ’
 41вҶ’  // Message data length (uint32_t)
 42вҶ’  uint32_t msg_size = static_cast<uint32_t>(data_size);
 43вҶ’  write_le(serialized_data_, msg_size);
 44вҶ’
 45вҶ’  // Message data (CDR bytes) using memcpy
 46вҶ’  size_t old_size = serialized_data_.size();
 47вҶ’  serialized_data_.resize(old_size + msg_size);
 48вҶ’  std::memcpy(serialized_data_.data() + old_size, data, msg_size);
 49вҶ’}
 50вҶ’
 51вҶ’void AggregatedMessageSerializer::clear() {
 52вҶ’  serialized_data_.clear();
 53вҶ’  message_count_ = 0;
 54вҶ’}
