 57вҶ’  return message_count_;
 58вҶ’}
 59вҶ’
 60вҶ’std::vector<uint8_t> AggregatedMessageSerializer::finalize() {
 61вҶ’  // Build 16-byte header (uncompressed)
 62вҶ’  std::vector<uint8_t> header(kBinaryHeaderSize);
 63вҶ’
 64вҶ’  // Magic (offset 0, 4 bytes, little-endian)
 65вҶ’  uint32_t magic = kBinaryFrameMagic;
 66вҶ’  std::memcpy(header.data(), &magic, sizeof(magic));
 67вҶ’
 68вҶ’  // Message count (offset 4, 4 bytes, little-endian)
 69вҶ’  uint32_t count = static_cast<uint32_t>(message_count_);
 70вҶ’  std::memcpy(header.data() + 4, &count, sizeof(count));
 71вҶ’
 72вҶ’  // Uncompressed size (offset 8, 4 bytes, little-endian)
 73вҶ’  uint32_t uncompressed = static_cast<uint32_t>(serialized_data_.size());
 74вҶ’  std::memcpy(header.data() + 8, &uncompressed, sizeof(uncompressed));
 75вҶ’
 76вҶ’  // Flags (offset 12, 4 bytes, reserved = 0)
 77вҶ’  uint32_t flags = 0;
 78вҶ’  std::memcpy(header.data() + 12, &flags, sizeof(flags));
 79вҶ’
 80вҶ’  // Handle empty payload case
 81вҶ’  if (serialized_data_.empty()) {
 82вҶ’    return header;
 83вҶ’  }
 84вҶ’
 85вҶ’  // Compress the payload
 86вҶ’  size_t max_compressed = ZSTD_compressBound(serialized_data_.size());
 87вҶ’  std::vector<uint8_t> result(kBinaryHeaderSize + max_compressed);
 88вҶ’
 89вҶ’  // Copy header to output
 90вҶ’  std::memcpy(result.data(), header.data(), kBinaryHeaderSize);
 91вҶ’
 92вҶ’  // Compress payload after header
 93вҶ’  size_t compressed_size = ZSTD_compress(
 94вҶ’      result.data() + kBinaryHeaderSize, max_compressed, serialized_data_.data(), serialized_data_.size(),
 95вҶ’      1  // compression level
 96вҶ’  );
 97вҶ’
 98вҶ’  if (ZSTD_isError(compressed_size)) {
 99вҶ’    throw std::runtime_error(std::string("ZSTD compression failed: ") + ZSTD_getErrorName(compressed_size));
100вҶ’  }
101вҶ’
102вҶ’  // Resize to actual size: header + compressed payload
103вҶ’  result.resize(kBinaryHeaderSize + compressed_size);
104вҶ’  return result;
105вҶ’}
106вҶ’
107вҶ’void AggregatedMessageSerializer::compress_zstd(
108вҶ’    const std::vector<uint8_t> &data, std::vector<uint8_t> &compressed_data) {
109вҶ’  compressed_data.clear();
110вҶ’  if (data.empty()) {
111вҶ’    return;
112вҶ’  }
113вҶ’
114вҶ’  // Get maximum compressed size
115вҶ’  size_t max_compressed_size = ZSTD_compressBound(data.size());
116вҶ’  compressed_data.resize(max_compressed_size);
117вҶ’
118вҶ’  // Compress
119вҶ’  size_t compressed_size = ZSTD_compress(compressed_data.data(), compressed_data.size(), data.data(), data.size(), 1);
120вҶ’
121вҶ’  // Check for errors
122вҶ’  if (ZSTD_isError(compressed_size)) {
123вҶ’    throw std::runtime_error(std::string("ZSTD compression failed: ") + ZSTD_getErrorName(compressed_size));
124вҶ’  }
125вҶ’
126вҶ’  // Resize to actual compressed size
127вҶ’  compressed_data.resize(compressed_size);
128вҶ’}
129вҶ’
130вҶ’void AggregatedMessageSerializer::decompress_zstd(
131вҶ’    const std::vector<uint8_t> &compressed_data, std::vector<uint8_t> &decompressed) {
132вҶ’  decompressed.clear();
133вҶ’  if (compressed_data.empty()) {
134вҶ’    return;
135вҶ’  }
136вҶ’
137вҶ’  // Get decompressed size
138вҶ’  unsigned long long decompressed_size = ZSTD_getFrameContentSize(compressed_data.data(), compressed_data.size());
139вҶ’
140вҶ’  if (decompressed_size == ZSTD_CONTENTSIZE_ERROR) {
141вҶ’    throw std::runtime_error("ZSTD: not compressed by zstd");
142вҶ’  }
143вҶ’  if (decompressed_size == ZSTD_CONTENTSIZE_UNKNOWN) {
144вҶ’    throw std::runtime_error("ZSTD: original size unknown");
145вҶ’  }
146вҶ’  decompressed.resize(decompressed_size);
147вҶ’
148вҶ’  // Decompress
149вҶ’  size_t result =
150вҶ’      ZSTD_decompress(decompressed.data(), decompressed.size(), compressed_data.data(), compressed_data.size());
151вҶ’
152вҶ’  // Check for errors
153вҶ’  if (ZSTD_isError(result)) {
154вҶ’    throw std::runtime_error(std::string("ZSTD decompression failed: ") + ZSTD_getErrorName(result));
155вҶ’  }
156вҶ’}
157вҶ’
158вҶ’template <typename T>
159вҶ’void AggregatedMessageSerializer::write_le(std::vector<uint8_t> &buffer, T value) {
160вҶ’  // Write value in little-endian format
161вҶ’  for (size_t i = 0; i < sizeof(T); ++i) {
162вҶ’    buffer.push_back(static_cast<uint8_t>((value >> (i * 8)) & 0xFF));
163вҶ’  }
164вҶ’}
165вҶ’
166вҶ’void AggregatedMessageSerializer::write_str(std::vector<uint8_t> &buffer, const std::string &str) {
167вҶ’  // Write string length
168вҶ’  write_le<uint16_t>(buffer, static_cast<uint16_t>(str.size()));
169вҶ’  // Write string data
170вҶ’  buffer.insert(buffer.end(), str.begin(), str.end());
171вҶ’}
172вҶ’
173вҶ’// Explicit template instantiations
174вҶ’template void AggregatedMessageSerializer::write_le<uint16_t>(std::vector<uint8_t> &, uint16_t);
175вҶ’template void AggregatedMessageSerializer::write_le<uint32_t>(std::vector<uint8_t> &, uint32_t);
176вҶ’template void AggregatedMessageSerializer::write_le<uint64_t>(std::vector<uint8_t> &, uint64_t);
