 46вҶ’                                          ix::WebSocket& web_socket, const ix::WebSocketMessagePtr& msg) {
 47вҶ’    {
 48вҶ’      std::lock_guard<std::mutex> state_lock(state_mutex_);
 49вҶ’      if (!initialized_) {
 50вҶ’        return;
 51вҶ’      }
 52вҶ’    }
 53вҶ’
 54вҶ’    std::string client_id = connection_state->getId();
 55вҶ’
 56вҶ’    if (msg->type == ix::WebSocketMessageType::Open) {
 57вҶ’      {
 58вҶ’        std::lock_guard<std::mutex> clients_lock(clients_mutex_);
 59вҶ’        for (const auto& client : server_->getClients()) {
