 61вҶ’            clients_[client_id] = client;
 62вҶ’            break;
 63вҶ’          }
 64вҶ’        }
 65вҶ’      }
 66вҶ’
 67вҶ’      ConnectionCallback cb;
 68вҶ’      {
 69вҶ’        std::lock_guard<std::mutex> state_lock(state_mutex_);
 70вҶ’        cb = on_connect_;
 71вҶ’      }
 72вҶ’      if (cb) {
 73вҶ’        cb(client_id);
 74вҶ’      }
 75вҶ’
 76вҶ’    } else if (msg->type == ix::WebSocketMessageType::Close) {
 77вҶ’      ConnectionCallback cb;
 78вҶ’      {
 79вҶ’        std::lock_guard<std::mutex> state_lock(state_mutex_);
 80вҶ’        cb = on_disconnect_;
 81вҶ’      }
 82вҶ’      if (cb) {
 83вҶ’        cb(client_id);
 84вҶ’      }
 85вҶ’
 86вҶ’      {
 87вҶ’        std::lock_guard<std::mutex> clients_lock(clients_mutex_);
 88вҶ’        clients_.erase(client_id);
 89вҶ’      }
 90вҶ’
 91вҶ’    } else if (msg->type == ix::WebSocketMessageType::Message) {
 92вҶ’      if (!msg->binary) {
 93вҶ’        IncomingRequest req;
 94вҶ’        req.client_id = client_id;
 95вҶ’        req.data.assign(msg->str.begin(), msg->str.end());
 96вҶ’
 97вҶ’        {
 98вҶ’          std::lock_guard<std::mutex> queue_lock(queue_mutex_);
 99вҶ’          incoming_queue_.push(std::move(req));
100вҶ’        }
101вҶ’        queue_cv_.notify_one();
102вҶ’      }
103вҶ’    }
104вҶ’  });
105вҶ’
106вҶ’  auto listen_result = server_->listen();
107вҶ’  if (!listen_result.first) {
108вҶ’    server_.reset();
109вҶ’    return tl::unexpected<std::string>(
110вҶ’        "Failed to listen on port " + std::to_string(port) + ": " + listen_result.second);
111вҶ’  }
112вҶ’
113вҶ’  server_->start();
114вҶ’  initialized_ = true;
