119вҶ’void WebSocketMiddleware::shutdown() {
120вҶ’  std::shared_ptr<ix::WebSocketServer> server_to_stop;
121вҶ’
122вҶ’  {
123вҶ’    std::lock_guard<std::mutex> lock(state_mutex_);
124вҶ’
125вҶ’    if (!initialized_) {
126вҶ’      return;
127вҶ’    }
128вҶ’
129вҶ’    initialized_ = false;
130вҶ’    on_connect_ = nullptr;
131вҶ’    on_disconnect_ = nullptr;
132вҶ’    server_to_stop = std::move(server_);
133вҶ’  }
134вҶ’
135вҶ’  queue_cv_.notify_all();
136вҶ’
137вҶ’  if (server_to_stop) {
138вҶ’    // Replace the message callback with a no-op before stopping. The original
139вҶ’    // callback captures `this`, so it must not fire after the WebSocketMiddleware
140вҶ’    // instance is destroyed (which can happen if the stop thread is detached on timeout).
141вҶ’    server_to_stop->setOnClientMessageCallback(
142вҶ’        [](std::shared_ptr<ix::ConnectionState>, ix::WebSocket&, const ix::WebSocketMessagePtr&) {});
143вҶ’
144вҶ’    // Initiate graceful close on all connected clients before calling stop().
145вҶ’    spdlog::debug("[shutdown] Pre-closing {} WebSocket client(s)...", server_to_stop->getClients().size());
146вҶ’    for (const auto& client : server_to_stop->getClients()) {
147вҶ’      client->close();
148вҶ’    }
149вҶ’
150вҶ’    // Run stop() on a dedicated thread with a timeout.
151вҶ’    spdlog::debug("[shutdown] Starting server stop thread...");
152вҶ’    auto done = std::make_shared<std::atomic<bool>>(false);
153вҶ’    std::thread stop_thread([server_to_stop, done]() {
154вҶ’      server_to_stop->stop();
155вҶ’      done->store(true);
156вҶ’    });
157вҶ’
158вҶ’    auto start = std::chrono::steady_clock::now();
159вҶ’    auto deadline = start + std::chrono::seconds(kShutdownTimeoutSeconds);
160вҶ’    while (!done->load() && std::chrono::steady_clock::now() < deadline) {
161вҶ’      std::this_thread::sleep_for(std::chrono::milliseconds(50));
162вҶ’    }
163вҶ’    auto elapsed_ms =
164вҶ’        std::chrono::duration_cast<std::chrono::milliseconds>(std::chrono::steady_clock::now() - start).count();
165вҶ’
166вҶ’    if (done->load()) {
167вҶ’      stop_thread.join();
168вҶ’      spdlog::debug("[shutdown] Server stop completed (took {}ms)", elapsed_ms);
169вҶ’    } else {
170вҶ’      // Timeout reached. Detach the thread and let it finish in the background.
171вҶ’      // The thread captures server_to_stop by shared_ptr, so the server
172вҶ’      // will be destroyed when stop() finishes and the thread exits.
173вҶ’      // The message callback was already cleared above, so no use-after-free.
174вҶ’      spdlog::warn(
175вҶ’          "[shutdown] Server stop timed out after {}s ({}ms elapsed), detaching shutdown thread",
176вҶ’          kShutdownTimeoutSeconds, elapsed_ms);
177вҶ’      stop_thread.detach();
178вҶ’    }
179вҶ’  }
180вҶ’
181вҶ’  {
182вҶ’    std::lock_guard<std::mutex> clients_lock(clients_mutex_);
183вҶ’    clients_.clear();
184вҶ’  }
185вҶ’
186вҶ’  {
187вҶ’    std::lock_guard<std::mutex> queue_lock(queue_mutex_);
188вҶ’    std::queue<IncomingRequest> empty;
189вҶ’    std::swap(incoming_queue_, empty);
190вҶ’  }
191вҶ’}
