193вҶ’bool WebSocketMiddleware::receive_request(std::vector<uint8_t>& data, std::string& client_identity) {
194вҶ’  {
195вҶ’    std::lock_guard<std::mutex> state_lock(state_mutex_);
196вҶ’    if (!initialized_) {
