198вҶ’    }
199вҶ’  }
200вҶ’
201вҶ’  std::unique_lock<std::mutex> lock(queue_mutex_);
202вҶ’
203вҶ’  if (!queue_cv_.wait_for(
204вҶ’          lock, std::chrono::milliseconds(kReceiveTimeoutMs), [this]() { return !incoming_queue_.empty(); })) {
205вҶ’    return false;
206вҶ’  }
207вҶ’
208вҶ’  auto req = std::move(incoming_queue_.front());
209вҶ’  incoming_queue_.pop();
