138вҶ’// Helper: wait for the ix::WebSocket client to reach Open state (up to timeout_ms).
139вҶ’static bool wait_for_client_open(ix::WebSocket& client, int timeout_ms = 2000) {
140вҶ’  auto deadline = std::chrono::steady_clock::now() + std::chrono::milliseconds(timeout_ms);
141вҶ’  while (std::chrono::steady_clock::now() < deadline) {
142вҶ’    if (client.getReadyState() == ix::ReadyState::Open) {
143вҶ’      return true;
144вҶ’    }
145вҶ’    std::this_thread::sleep_for(std::chrono::milliseconds(10));
146вҶ’  }
147вҶ’  return false;
148вҶ’}
149вҶ’
150вҶ’// Helper: poll receive_request() in a loop until it succeeds or we time out.
151вҶ’static bool poll_receive_request(
152вҶ’    WebSocketMiddleware& mw, std::vector<uint8_t>& data, std::string& client_id, int timeout_ms = 2000) {
153вҶ’  auto deadline = std::chrono::steady_clock::now() + std::chrono::milliseconds(timeout_ms);
154вҶ’  while (std::chrono::steady_clock::now() < deadline) {
155вҶ’    if (mw.receive_request(data, client_id)) {
156вҶ’      return true;
157вҶ’    }
158вҶ’  }
159вҶ’  return false;
160вҶ’}
