36вҶ’bool Ros2SubscriptionManager::subscribe(const std::string& topic_name, const std::string& topic_type) {
37вҶ’  // Create a ROS2 callback that converts SerializedMessage вҶ’ vector<byte> and calls the stored callback
38вҶ’  Ros2MessageCallback ros2_callback = [this, topic_type](
39вҶ’                                          const std::string& topic, const std::shared_ptr<rclcpp::SerializedMessage>& msg,
40вҶ’                                          uint64_t receive_time_ns) {
41вҶ’    // Optionally strip large fields
42вҶ’    const rclcpp::SerializedMessage* msg_to_use = msg.get();
43вҶ’    std::unique_ptr<rclcpp::SerializedMessage> stripped_msg;
44вҶ’
45вҶ’    if (strip_large_messages_ && MessageStripper::should_strip(topic_type)) {
46вҶ’      try {
47вҶ’        stripped_msg = std::make_unique<rclcpp::SerializedMessage>(MessageStripper::strip(topic_type, *msg));
48вҶ’        msg_to_use = stripped_msg.get();
49вҶ’      } catch (const std::exception& e) {
50вҶ’        spdlog::warn("Failed to strip message on topic '{}': {}. Forwarding original.", topic, e.what());
51вҶ’      }
52вҶ’    }
53вҶ’
54вҶ’    // Convert rclcpp::SerializedMessage to shared_ptr<vector<byte>>
55вҶ’    const auto& rcl_msg = msg_to_use->get_rcl_serialized_message();
56вҶ’    auto data = std::make_shared<std::vector<std::byte>>(rcl_msg.buffer_length);
57вҶ’    std::memcpy(data->data(), rcl_msg.buffer, rcl_msg.buffer_length);
58вҶ’
59вҶ’    // Invoke the stored callback
60вҶ’    MessageCallback cb;
61вҶ’    {
62вҶ’      std::lock_guard<std::mutex> lock(callback_mutex_);
63вҶ’      cb = callback_;
64вҶ’    }
65вҶ’    if (cb) {
66вҶ’      cb(topic, std::move(data), receive_time_ns);
67вҶ’    }
68вҶ’  };
69вҶ’
70вҶ’  return inner_manager_.subscribe(topic_name, topic_type, ros2_callback);
71вҶ’}
