 50вҶ’      node->get_logger(),
 51вҶ’      "Configuration: port=%d, publish_rate=%.1f Hz, session_timeout=%.1f s, strip_large_messages=%s", port,
 52вҶ’      publish_rate, session_timeout, strip_large_messages ? "true" : "false");
 53вҶ’
 54вҶ’  try {
