 56вҶ’    auto topic_source = std::make_shared<pj_bridge::Ros2TopicSource>(node);
 57вҶ’    auto sub_manager = std::make_shared<pj_bridge::Ros2SubscriptionManager>(node, strip_large_messages);
 58вҶ’    auto middleware = std::make_shared<pj_bridge::WebSocketMiddleware>();
 59вҶ’
 60вҶ’    // Create bridge server
 61вҶ’    pj_bridge::BridgeServer server(topic_source, sub_manager, middleware, port, session_timeout, publish_rate);
 62вҶ’
 63вҶ’    if (!server.initialize()) {
 64вҶ’      RCLCPP_ERROR(node->get_logger(), "Failed to initialize bridge server");
 65вҶ’      rclcpp::shutdown();
