109вҶ’bool BridgeServer::process_requests() {
110вҶ’  if (!initialized_) {
111вҶ’    spdlog::error("Bridge server not initialized");
112вҶ’    return false;
113вҶ’  }
114вҶ’
115вҶ’  // Receive request (non-blocking with timeout)
116вҶ’  std::vector<uint8_t> request_data;
117вҶ’  std::string client_id;
118вҶ’  bool received = middleware_->receive_request(request_data, client_id);
119вҶ’
120вҶ’  if (!received || request_data.empty()) {
121вҶ’    return false;
122вҶ’  }
123вҶ’
124вҶ’  std::string request(request_data.begin(), request_data.end());
125вҶ’  if (client_id.empty()) {
126вҶ’    spdlog::warn("Received request with no client identity");
127вҶ’    return true;
128вҶ’  }
129вҶ’
130вҶ’  // Parse request JSON
131вҶ’  std::string response;
132вҶ’  json request_json;
133вҶ’  try {
134вҶ’    request_json = json::parse(request);
135вҶ’
136вҶ’    if (!request_json.contains("command")) {
137вҶ’      response = create_error_response("INVALID_REQUEST", "Missing 'command' field", request_json);
138вҶ’    } else {
139вҶ’      std::string command = request_json["command"];
140вҶ’
141вҶ’      spdlog::debug("Processing '{}' command from client '{}'", command, client_id);
142вҶ’
143вҶ’      if (command == "get_topics") {
144вҶ’        response = handle_get_topics(client_id, request_json);
145вҶ’      } else if (command == "subscribe") {
146вҶ’        response = handle_subscribe(client_id, request_json);
147вҶ’      } else if (command == "unsubscribe") {
148вҶ’        response = handle_unsubscribe(client_id, request_json);
149вҶ’      } else if (command == "heartbeat") {
150вҶ’        response = handle_heartbeat(client_id, request_json);
151вҶ’      } else if (command == "pause") {
152вҶ’        response = handle_pause(client_id, request_json);
153вҶ’      } else if (command == "resume") {
154вҶ’        response = handle_resume(client_id, request_json);
155вҶ’      } else {
156вҶ’        response = create_error_response("UNKNOWN_COMMAND", "Unknown command: " + command, request_json);
157вҶ’      }
158вҶ’    }
159вҶ’  } catch (const json::exception& e) {
160вҶ’    spdlog::error("JSON parse error: {}", e.what());
161вҶ’    response = create_error_response("INVALID_JSON", "Failed to parse JSON request", json::object());
162вҶ’  } catch (const std::exception& e) {
163вҶ’    spdlog::error("Error processing request: {}", e.what());
164вҶ’    response = create_error_response("INTERNAL_ERROR", "Internal server error", request_json);
165вҶ’  }
166вҶ’
167вҶ’  // Send response to the specific client
168вҶ’  std::vector<uint8_t> response_data(response.begin(), response.end());
169вҶ’  if (!middleware_->send_reply(client_id, response_data)) {
170вҶ’    spdlog::warn("Failed to send response to client '{}', cleaning up session", client_id);
171вҶ’    cleanup_session(client_id);
172вҶ’  }
173вҶ’  return true;
174вҶ’}
