204вҶ’std::string BridgeServer::handle_subscribe(const std::string& client_id, const nlohmann::json& request) {
205вҶ’  if (!session_manager_->session_exists(client_id)) {
206вҶ’    session_manager_->create_session(client_id);
207вҶ’    spdlog::info("Created new session for client '{}'", client_id);
208вҶ’  }
209вҶ’
210вҶ’  session_manager_->update_heartbeat(client_id);
211вҶ’
212вҶ’  if (!request.contains("topics")) {
213вҶ’    return create_error_response("INVALID_REQUEST", "Missing 'topics' field", request);
214вҶ’  }
215вҶ’
216вҶ’  if (!request["topics"].is_array()) {
217вҶ’    return create_error_response("INVALID_REQUEST", "'topics' must be an array", request);
218вҶ’  }
219вҶ’
220вҶ’  auto current_subs = session_manager_->get_subscriptions(client_id);
221вҶ’
222вҶ’  // Parse requested topics вҖ” supports mixed array of strings and objects:
223вҶ’  //   ["topic1", {"name": "topic2", "max_rate_hz": 10.0}]
224вҶ’  std::unordered_map<std::string, double> requested_topics;
225вҶ’  for (const auto& topic : request["topics"]) {
226вҶ’    if (topic.is_string()) {
227вҶ’      requested_topics[topic.get<std::string>()] = 0.0;
228вҶ’    } else if (topic.is_object() && topic.contains("name") && topic["name"].is_string()) {
229вҶ’      double rate_hz = 0.0;
