189вҶ’TEST_F(MessageBufferTest, AutoCleanupOldMessages) {
190вҶ’  // Use a buffer with a short max age (20ms) so we can test cleanup quickly.
191вҶ’  // Cleanup is based on received_at_ns (wall-clock time when add_message is called),
192вҶ’  // not the user-provided timestamp_ns.
193вҶ’  MessageBuffer short_lived_buffer(20'000'000);  // 20ms max age
194вҶ’
195вҶ’  std::vector<uint8_t> data = {1, 2, 3};
196вҶ’  uint64_t current_time_ns = get_current_time_ns();
197вҶ’
198вҶ’  // Add first message
199вҶ’  short_lived_buffer.add_message("topic1", current_time_ns, create_test_data(data));
200вҶ’
201вҶ’  // Wait long enough for the first message to become "old" by received_at_ns
202вҶ’  std::this_thread::sleep_for(std::chrono::milliseconds(30));
203вҶ’
204вҶ’  // Add second message вҖ” this triggers cleanup, which should evict topic1
205вҶ’  short_lived_buffer.add_message("topic2", current_time_ns, create_test_data(data));
206вҶ’
207вҶ’  // The old message should have been cleaned up automatically
208вҶ’  EXPECT_EQ(short_lived_buffer.size(), 1);
209вҶ’
210вҶ’  std::unordered_map<std::string, std::deque<BufferedMessage>> messages;
211вҶ’  short_lived_buffer.move_messages(messages);
212вҶ’  EXPECT_EQ(messages.size(), 1);
213вҶ’  EXPECT_TRUE(messages.find("topic2") != messages.end());
214вҶ’  EXPECT_TRUE(messages.find("topic1") == messages.end());
215вҶ’}
