 28вҶ’class MessageSerializerTest : public ::testing::Test {
 29вҶ’ protected:
 30вҶ’  AggregatedMessageSerializer serializer_;
 31вҶ’
 32вҶ’  // Helper to create test data as a vector of bytes
 33вҶ’  std::vector<std::byte> create_test_data(const std::vector<uint8_t>& data) {
 34вҶ’    std::vector<std::byte> result(data.size());
 35вҶ’    for (size_t i = 0; i < data.size(); ++i) {
 36вҶ’      result[i] = static_cast<std::byte>(data[i]);
 37вҶ’    }
 38вҶ’    return result;
 39вҶ’  }
 40вҶ’
 41вҶ’  // Helper to read little-endian values from buffer
 42вҶ’  template <typename T>
 43вҶ’  T read_le(const std::vector<uint8_t>& buffer, size_t& offset) {
 44вҶ’    T value = 0;
 45вҶ’    for (size_t i = 0; i < sizeof(T); ++i) {
 46вҶ’      value |= static_cast<T>(buffer[offset++]) << (i * 8);
 47вҶ’    }
 48вҶ’    return value;
 49вҶ’  }
 50вҶ’};
