 58вҶ’TEST_F(MessageSerializerTest, SerializeSingleMessage) {
 59вҶ’  std::string topic = "/test_topic";
 60вҶ’  uint64_t timestamp = 1234567890123456789ULL;
 61вҶ’  std::vector<uint8_t> raw_data = {0xAA, 0xBB, 0xCC};
 62вҶ’
 63вҶ’  auto data = create_test_data(raw_data);
 64вҶ’  serializer_.serialize_message(topic, timestamp, data.data(), data.size());
 65вҶ’
 66вҶ’  const auto& serialized = serializer_.get_serialized_data();
 67вҶ’
 68вҶ’  // Parse serialized data
 69вҶ’  size_t offset = 0;
 70вҶ’
 71вҶ’  // Topic name length
 72вҶ’  uint16_t topic_len = read_le<uint16_t>(serialized, offset);
 73вҶ’  EXPECT_EQ(topic_len, topic.size());
 74вҶ’
 75вҶ’  // Topic name
 76вҶ’  std::string parsed_topic(serialized.begin() + offset, serialized.begin() + offset + topic_len);
 77вҶ’  offset += topic_len;
 78вҶ’  EXPECT_EQ(parsed_topic, topic);
 79вҶ’
 80вҶ’  // Timestamp
 81вҶ’  uint64_t parsed_timestamp = read_le<uint64_t>(serialized, offset);
 82вҶ’  EXPECT_EQ(parsed_timestamp, timestamp);
 83вҶ’
 84вҶ’  // Data length (uint32_t)
 85вҶ’  uint32_t data_len = read_le<uint32_t>(serialized, offset);
 86вҶ’  EXPECT_EQ(data_len, raw_data.size());
 87вҶ’
 88вҶ’  // Data
 89вҶ’  std::vector<uint8_t> parsed_data(serialized.begin() + offset, serialized.begin() + offset + data_len);
 90вҶ’  EXPECT_EQ(parsed_data, raw_data);
 91вҶ’}
