 93вҶ’TEST_F(MessageSerializerTest, SerializeMultipleMessages) {
 94вҶ’  // Add 3 messages with different data
 95вҶ’  auto data1 = create_test_data({0x01, 0x02});
 96вҶ’  auto data2 = create_test_data({0x03, 0x04, 0x05});
 97вҶ’  auto data3 = create_test_data({0x06});
 98вҶ’
 99вҶ’  serializer_.serialize_message("/topic1", 100, data1.data(), data1.size());
100вҶ’  serializer_.serialize_message("/topic2", 200, data2.data(), data2.size());
101вҶ’  serializer_.serialize_message("/topic3", 300, data3.data(), data3.size());
102вҶ’
103вҶ’  const auto& serialized = serializer_.get_serialized_data();
104вҶ’
105вҶ’  size_t offset = 0;
106вҶ’
107вҶ’  // Verify we can parse all three messages
108вҶ’  for (int i = 0; i < 3; ++i) {
109вҶ’    uint16_t topic_len = read_le<uint16_t>(serialized, offset);
110вҶ’    EXPECT_GT(topic_len, 0);
111вҶ’
112вҶ’    offset += topic_len;  // Skip topic name
113вҶ’    offset += 8;          // Skip timestamp
114вҶ’
115вҶ’    uint32_t data_len = read_le<uint32_t>(serialized, offset);
116вҶ’    EXPECT_GT(data_len, 0);
