310вҶ’TEST_F(MessageSerializerTest, WireFormatMatchesProjectSpec) {
311вҶ’  // PROJECT.md spec:
312вҶ’  //   - topic name: uint16_t length + N bytes
313вҶ’  //   - timestamp: uint64_t nanoseconds
314вҶ’  //   - data: uint32_t length + N bytes
315вҶ’  // Total for "/t" topic, 2-byte data = 2 + 2 + 8 + 4 + 2 = 18 bytes
316вҶ’
317вҶ’  std::string topic = "/t";
318вҶ’  uint64_t timestamp = 42;
319вҶ’  std::vector<uint8_t> raw_data = {0xAA, 0xBB};
320вҶ’
321вҶ’  auto data = create_test_data(raw_data);
322вҶ’  serializer_.serialize_message(topic, timestamp, data.data(), data.size());
323вҶ’
324вҶ’  const auto& serialized = serializer_.get_serialized_data();
325вҶ’
326вҶ’  // Expected total size: 2(topic_len) + 2(topic) + 8(timestamp) + 4(data_len) + 2(data) = 18
327вҶ’  EXPECT_EQ(serialized.size(), 18u);
328вҶ’
329вҶ’  size_t offset = 0;
330вҶ’
331вҶ’  // Topic name length (uint16_t)
332вҶ’  uint16_t topic_len = read_le<uint16_t>(serialized, offset);
333вҶ’  EXPECT_EQ(topic_len, 2u);
334вҶ’
335вҶ’  // Topic name
336вҶ’  std::string parsed_topic(serialized.begin() + offset, serialized.begin() + offset + topic_len);
337вҶ’  offset += topic_len;
338вҶ’  EXPECT_EQ(parsed_topic, "/t");
339вҶ’
340вҶ’  // Single timestamp (uint64_t)
341вҶ’  uint64_t parsed_ts = read_le<uint64_t>(serialized, offset);
342вҶ’  EXPECT_EQ(parsed_ts, 42u);
343вҶ’
344вҶ’  // Data length (uint32_t)
345вҶ’  uint32_t data_len = read_le<uint32_t>(serialized, offset);
346вҶ’  EXPECT_EQ(data_len, 2u);
347вҶ’
348вҶ’  // Data
349вҶ’  EXPECT_EQ(serialized[offset], 0xAA);
350вҶ’  EXPECT_EQ(serialized[offset + 1], 0xBB);
351вҶ’}
