 32вҶ’std::string SchemaExtractor::get_message_definition(const std::string& message_type) {
 33вҶ’  {
 34вҶ’    std::shared_lock<std::shared_mutex> lock(cache_mutex_);
 35вҶ’    auto it = definition_cache_.find(message_type);
 36вҶ’    if (it != definition_cache_.end()) {
 37вҶ’      return it->second;
 38вҶ’    }
 39вҶ’  }
 40вҶ’
 41вҶ’  std::string package_name;
 42вҶ’  std::string type_name;
 43вҶ’
 44вҶ’  if (!parse_message_type(message_type, package_name, type_name)) {
 45вҶ’    return "";
 46вҶ’  }
 47вҶ’
 48вҶ’  std::ostringstream result;
 49вҶ’  std::set<std::string> processed_types;
 50вҶ’
 51вҶ’  if (!build_message_definition_recursive(package_name, type_name, result, processed_types, true)) {
 52вҶ’    return "";
 53вҶ’  }
 54вҶ’
 55вҶ’  std::string definition = result.str();
 56вҶ’
 57вҶ’  {
 58вҶ’    std::unique_lock<std::shared_mutex> lock(cache_mutex_);
 59вҶ’    definition_cache_[message_type] = definition;
 60вҶ’  }
 61вҶ’
 62вҶ’  return definition;
 63вҶ’}
 64вҶ’
 65вҶ’bool SchemaExtractor::build_message_definition_recursive(
 66вҶ’    const std::string& package_name, const std::string& type_name, std::ostringstream& output,
 67вҶ’    std::set<std::string>& processed_types, bool is_root) const {
 68вҶ’  const std::string full_type = package_name + "/" + type_name;
 69вҶ’
 70вҶ’  std::string msg_content;
 71вҶ’  {
 72вҶ’    std::shared_lock<std::shared_mutex> lock(cache_mutex_);
 73вҶ’    auto it = msg_file_cache_.find(full_type);
 74вҶ’    if (it != msg_file_cache_.end()) {
 75вҶ’      msg_content = it->second;
 76вҶ’    }
 77вҶ’  }
 78вҶ’
 79вҶ’  if (msg_content.empty()) {
 80вҶ’    std::string package_share_dir;
 81вҶ’    try {
 82вҶ’      package_share_dir = ament_index_cpp::get_package_share_directory(package_name);
 83вҶ’    } catch (const std::exception& e) {
 84вҶ’      return false;
 85вҶ’    }
 86вҶ’
 87вҶ’    std::string msg_file_path = package_share_dir + "/msg/" + type_name + ".msg";
 88вҶ’
 89вҶ’    std::ifstream msg_file(msg_file_path);
 90вҶ’    if (!msg_file.is_open()) {
 91вҶ’      return false;
 92вҶ’    }
