26вҶ’std::vector<TopicInfo> TopicDiscovery::discover_topics() {
27вҶ’  topics_.clear();
28вҶ’
29вҶ’  auto topic_names_and_types = node_->get_topic_names_and_types();
30вҶ’
31вҶ’  for (const auto& [topic_name, topic_types] : topic_names_and_types) {
32вҶ’    if (should_filter_topic(topic_name)) {
33вҶ’      continue;
34вҶ’    }
35вҶ’
36вҶ’    if (!topic_types.empty()) {
37вҶ’      TopicInfo info;
38вҶ’      info.name = topic_name;
39вҶ’      info.type = topic_types[0];
40вҶ’      topics_.push_back(info);
41вҶ’    }
42вҶ’  }
43вҶ’
44вҶ’  return topics_;
45вҶ’}
