51вҶ’bool TopicDiscovery::refresh() {
52вҶ’  try {
53вҶ’    discover_topics();
54вҶ’    return true;
55вҶ’  } catch (const std::exception& e) {
56вҶ’    RCLCPP_ERROR(node_->get_logger(), "Topic discovery refresh failed: %s", e.what());
57вҶ’    return false;
58вҶ’  }
