61вҶ’bool TopicDiscovery::should_filter_topic(const std::string& topic_name) const {
62вҶ’  static const std::vector<std::string> kSystemTopics = {"/rosout", "/parameter_events", "/robot_description"};
63вҶ’
64вҶ’  for (const auto& system_topic : kSystemTopics) {
65вҶ’    if (topic_name == system_topic) {
66вҶ’      return true;
67вҶ’    }
68вҶ’  }
69вҶ’
70вҶ’  if (topic_name.find("/_") == 0) {
71вҶ’    return true;
72вҶ’  }
73вҶ’
74вҶ’  return false;
75вҶ’}
