 26вҶ’class DdsTopicDiscovery::PublisherListener
 27вҶ’    : public dds::sub::NoOpDataReaderListener<dds::topic::PublicationBuiltinTopicData> {
 28вҶ’ public:
 29вҶ’  PublisherListener(DdsTopicDiscovery& discovery, int32_t domain_id) : discovery_(discovery), domain_id_(domain_id) {}
 30вҶ’
 31вҶ’  void on_data_available(dds::sub::DataReader<dds::topic::PublicationBuiltinTopicData>& reader) override {
 32вҶ’    try {
 33вҶ’      auto samples = reader.select().state(dds::sub::status::DataState::new_instance()).take();
 34вҶ’
 35вҶ’      for (const auto& sample : samples) {
 36вҶ’        if (!sample.info().valid()) {
 37вҶ’          continue;
 38вҶ’        }
 39вҶ’
 40вҶ’        const auto& topic_name = sample.data().topic_name();
 41вҶ’        const auto& type = sample.data().extensions().type();
 42вҶ’
 43вҶ’        if (!type) {
 44вҶ’          spdlog::debug("Topic '{}' discovered without type info in domain {}", topic_name.to_std_string(), domain_id_);
 45вҶ’          continue;
 46вҶ’        }
 47вҶ’
 48вҶ’        const auto& type_name = type->name();
 49вҶ’
 50вҶ’        if (type->kind() != dds::core::xtypes::TypeKind::STRUCTURE_TYPE) {
 51вҶ’          spdlog::debug("Topic '{}' has non-struct type '{}', skipping", topic_name.to_std_string(), type_name);
 52вҶ’          continue;
 53вҶ’        }
 54вҶ’
 55вҶ’        auto struct_type = static_cast<const dds::core::xtypes::StructType&>(type.get());
 56вҶ’
 57вҶ’        rti::core::xtypes::DynamicTypePrintFormatProperty print_format{
 58вҶ’            0, false, rti::core::xtypes::DynamicTypePrintKind::idl, true};
 59вҶ’        std::string schema_idl = rti::core::xtypes::to_string(type.get(), print_format);
 60вҶ’
 61вҶ’        spdlog::info(
 62вҶ’            "Discovered topic '{}' (type: '{}') in domain {}", topic_name.to_std_string(), type_name, domain_id_);
 63вҶ’
 64вҶ’        discovery_.on_topic_discovered(topic_name.to_std_string(), type_name, struct_type, schema_idl, domain_id_);
 65вҶ’      }
 66вҶ’    } catch (const std::exception& e) {
 67вҶ’      spdlog::error("Exception in PublisherListener on domain {}: {}", domain_id_, e.what());
 68вҶ’    }
 69вҶ’  }
 70вҶ’
 71вҶ’ private:
 72вҶ’  DdsTopicDiscovery& discovery_;
 73вҶ’  int32_t domain_id_;
 74вҶ’};
 75вҶ’
 76вҶ’DdsTopicDiscovery::DdsTopicDiscovery(const std::vector<int32_t>& domain_ids, const std::string& qos_profile_path) {
 77вҶ’  if (!qos_profile_path.empty()) {
 78вҶ’    rti::core::QosProviderParams params;
 79вҶ’    params.url_profile({qos_profile_path});
 80вҶ’    rti::core::default_qos_provider_params(params);
 81вҶ’    spdlog::info("Set default QoS profile from '{}'", qos_profile_path);
 82вҶ’  }
 83вҶ’
 84вҶ’  for (int32_t domain_id : domain_ids) {
 85вҶ’    spdlog::info("Creating DomainParticipant for domain {}", domain_id);
 86вҶ’
 87вҶ’    dds::domain::DomainParticipant participant(domain_id);
 88вҶ’    participants_.emplace(domain_id, participant);
 89вҶ’
 90вҶ’    auto listener = std::make_shared<PublisherListener>(*this, domain_id);
 91вҶ’    listeners_.push_back(listener);
 92вҶ’
 93вҶ’    dds::sub::Subscriber builtin_subscriber = dds::sub::builtin_subscriber(participant);
 94вҶ’    std::vector<dds::sub::DataReader<dds::topic::PublicationBuiltinTopicData>> readers;
 95вҶ’    dds::sub::find<dds::sub::DataReader<dds::topic::PublicationBuiltinTopicData>>(
 96вҶ’        builtin_subscriber, dds::topic::publication_topic_name(), std::back_inserter(readers));
 97вҶ’
 98вҶ’    if (readers.empty()) {
 99вҶ’      spdlog::error("No built-in publication DataReader found for domain {}", domain_id);
100вҶ’      continue;
101вҶ’    }
102вҶ’
103вҶ’    readers[0].set_listener(listener);
104вҶ’    builtin_readers_.push_back(std::move(readers[0]));
105вҶ’
106вҶ’    spdlog::info("Topic discovery active on domain {}", domain_id);
107вҶ’  }
108вҶ’}
109вҶ’
110вҶ’DdsTopicDiscovery::~DdsTopicDiscovery() {
111вҶ’  spdlog::debug("[shutdown] ~DdsTopicDiscovery: clearing {} builtin readers", builtin_readers_.size());
112вҶ’  for (auto& reader : builtin_readers_) {
113вҶ’    try {
114вҶ’      reader.set_listener(nullptr);
115вҶ’    } catch (const std::exception& e) {
116вҶ’      spdlog::warn("Error clearing builtin reader listener: {}", e.what());
117вҶ’    } catch (...) {
118вҶ’      spdlog::warn("Unknown error clearing builtin reader listener");
119вҶ’    }
120вҶ’  }
121вҶ’  builtin_readers_.clear();
122вҶ’  listeners_.clear();
123вҶ’  spdlog::debug("[shutdown] ~DdsTopicDiscovery: builtin readers cleared");
124вҶ’
125вҶ’  for (auto& [domain_id, participant] : participants_) {
126вҶ’    try {
127вҶ’      spdlog::debug("[shutdown] Closing DomainParticipant for domain {}...", domain_id);
128вҶ’      participant.close();
129вҶ’      spdlog::debug("[shutdown] DomainParticipant for domain {} closed", domain_id);
130вҶ’    } catch (const std::exception& e) {
131вҶ’      spdlog::warn("Error closing participant for domain {}: {}", domain_id, e.what());
132вҶ’    } catch (...) {
133вҶ’      spdlog::warn("Unknown error closing participant for domain {}", domain_id);
134вҶ’    }
135вҶ’  }
136вҶ’  spdlog::debug("[shutdown] ~DdsTopicDiscovery complete");
137вҶ’}
