139вҶ’void DdsTopicDiscovery::on_topic_discovered(
140вҶ’    const std::string& topic_name, const std::string& type_name, const dds::core::xtypes::StructType& struct_type,
141вҶ’    const std::string& schema_idl, int32_t domain_id) {
142вҶ’  std::unique_lock<std::shared_mutex> lock(mutex_);
143вҶ’
144вҶ’  if (topics_.find(topic_name) != topics_.end()) {
