351вҶ’TEST_F(WebSocketMiddlewareTest, ShutdownWithConnectedClientDoesNotDeadlock) {
352вҶ’  auto result = middleware_->initialize(18094);
353вҶ’  ASSERT_TRUE(result.has_value());
354вҶ’
355вҶ’  // Set a disconnect callback (simulates BridgeServer's callback).
356вҶ’  // The fix clears callbacks before server_->stop(), so this must NOT fire
357вҶ’  // during shutdown вҖ” otherwise it would call into a potentially dead object.
358вҶ’  std::atomic<bool> disconnect_fired{false};
359вҶ’  middleware_->set_on_disconnect([&](const std::string& /*client_id*/) { disconnect_fired.store(true); });
360вҶ’
361вҶ’  // Connect a real WebSocket client
362вҶ’  ix::WebSocket client;
363вҶ’  client.setUrl("ws://127.0.0.1:18094");
364вҶ’  client.setOnMessageCallback([](const ix::WebSocketMessagePtr& /*msg*/) {});
365вҶ’  client.start();
366вҶ’
367вҶ’  ASSERT_TRUE(wait_for_client_open(client)) << "Client failed to connect";
368вҶ’  std::this_thread::sleep_for(std::chrono::milliseconds(100));
369вҶ’
370вҶ’  // Call shutdown() in a separate thread so we can detect a deadlock via timeout.
371вҶ’  // Before the fix, shutdown() held state_mutex_ while calling server_->stop();
372вҶ’  // the Close event fired on IX IO threads tried to acquire the same mutex вҶ’ deadlock.
373вҶ’  std::atomic<bool> shutdown_completed{false};
374вҶ’  std::thread shutdown_thread([&]() {
375вҶ’    middleware_->shutdown();
376вҶ’    shutdown_completed.store(true);
377вҶ’  });
378вҶ’
379вҶ’  // Wait up to 5 seconds вҖ” far more than enough for a clean shutdown
380вҶ’  auto deadline = std::chrono::steady_clock::now() + std::chrono::seconds(5);
381вҶ’  while (!shutdown_completed.load() && std::chrono::steady_clock::now() < deadline) {
382вҶ’    std::this_thread::sleep_for(std::chrono::milliseconds(50));
383вҶ’  }
384вҶ’
385вҶ’  EXPECT_TRUE(shutdown_completed.load()) << "shutdown() deadlocked with a connected client";
386вҶ’
387вҶ’  if (shutdown_thread.joinable()) {
388вҶ’    shutdown_thread.join();
389вҶ’  }
390вҶ’
391вҶ’  EXPECT_FALSE(middleware_->is_ready());
392вҶ’
393вҶ’  // Disconnect callback must NOT have fired during shutdown вҖ” callbacks are
394вҶ’  // cleared before the server is stopped to prevent use-after-free.
395вҶ’  EXPECT_FALSE(disconnect_fired.load());
396вҶ’
397вҶ’  client.stop();
398вҶ’}
