 31вҶ’
 32вҶ’  void on_data_available(dds::sub::DataReader<dds::core::xtypes::DynamicData>& reader) override {
 33вҶ’    try {
 34вҶ’      auto samples = reader.take();
 35вҶ’
 36вҶ’      DdsMessageCallback cb;
 37вҶ’      {
 38вҶ’        std::lock_guard<std::mutex> lock(manager_.mutex_);
 39вҶ’        cb = manager_.callback_;
 40вҶ’      }
 41вҶ’
 42вҶ’      if (!cb) {
 43вҶ’        return;
 44вҶ’      }
 45вҶ’
 46вҶ’      for (const auto& sample : samples) {
 47вҶ’        if (!sample.info().valid()) {
 48вҶ’          continue;
 49вҶ’        }
 50вҶ’
 51вҶ’        auto cdr_buffer = sample.data().get_cdr_buffer();
 52вҶ’        const auto* raw_data = reinterpret_cast<const std::byte*>(cdr_buffer.first);
 53вҶ’        uint32_t data_size = cdr_buffer.second;
 54вҶ’
 55вҶ’        auto cdr_data = std::make_shared<std::vector<std::byte>>(raw_data, raw_data + data_size);
 56вҶ’
 57вҶ’        const auto& source_ts = sample.info().source_timestamp();
 58вҶ’        uint64_t timestamp_ns = (static_cast<uint64_t>(source_ts.sec()) * 1'000'000'000ULL) + source_ts.nanosec();
 59вҶ’
 60вҶ’        cb(topic_name_, std::move(cdr_data), timestamp_ns);
 61вҶ’      }
 62вҶ’    } catch (const std::exception& e) {
 63вҶ’      spdlog::error("Exception in DataReaderListener for '{}': {}", topic_name_, e.what());
 64вҶ’    }
 65вҶ’  }
 66вҶ’
 67вҶ’ private:
 68вҶ’  std::string topic_name_;
 69вҶ’  DdsSubscriptionManager& manager_;
