671вҶ’            uint64_t min_interval_ns = static_cast<uint64_t>(1'000'000'000'000) / static_cast<uint64_t>(rate_mhz);
672вҶ’            uint64_t last_sent = rep_last_sent[topic];
673вҶ’
674вҶ’            for (const auto& msg : msgs) {
675вҶ’              if (msg.timestamp_ns >= last_sent + min_interval_ns) {
676вҶ’                serializer.serialize_message(topic, msg.timestamp_ns, msg.data->data(), msg.data->size());
677вҶ’                last_sent = msg.timestamp_ns;
678вҶ’                group_msg_count++;
679вҶ’                forward_counts[topic]++;
680вҶ’              }
681вҶ’            }
682вҶ’            rep_last_sent[topic] = last_sent;
683вҶ’          }
684вҶ’        }
685вҶ’
686вҶ’        if (group_msg_count == 0) {
687вҶ’          continue;
688вҶ’        }
689вҶ’
690вҶ’        GroupFrame frame;
691вҶ’        frame.compressed_data = serializer.finalize();
692вҶ’        frame.msg_count = group_msg_count;
693вҶ’        frame.client_ids = client_ids;
694вҶ’
695вҶ’        // Propagate rate-limiting state to other clients in the group
696вҶ’        for (const auto& client_id : client_ids) {
697вҶ’          if (client_id != client_ids.front()) {
698вҶ’            last_sent_times_[client_id] = rep_last_sent;
699вҶ’          }
700вҶ’        }
701вҶ’
702вҶ’        frames.push_back(std::move(frame));
703вҶ’      }
704вҶ’    }  // last_sent_mutex_ released here
705вҶ’
706вҶ’    // Send frames outside of any lock
707вҶ’    for (const auto& frame : frames) {
708вҶ’      bool any_sent = false;
709вҶ’      for (const auto& client_id : frame.client_ids) {
710вҶ’        auto it = paused_state.find(client_id);
711вҶ’        if (it != paused_state.end() && it->second) {
712вҶ’          continue;
713вҶ’        }
714вҶ’        if (middleware_->send_binary(client_id, frame.compressed_data)) {
715вҶ’          any_sent = true;
716вҶ’        } else {
717вҶ’          spdlog::debug("Failed to send binary frame to client '{}'", client_id);
718вҶ’        }
719вҶ’      }
720вҶ’
721вҶ’      if (any_sent) {
722вҶ’        total_msg_count += frame.msg_count;
723вҶ’        total_bytes += frame.compressed_data.size();
724вҶ’      }
725вҶ’    }
726вҶ’
727вҶ’    if (total_msg_count > 0) {
728вҶ’      std::lock_guard<std::mutex> lock(stats_mutex_);
729вҶ’      total_messages_published_ += total_msg_count;
730вҶ’      total_bytes_published_ += total_bytes;
731вҶ’      publish_cycles_++;
732вҶ’      for (const auto& [topic, count] : forward_counts) {
733вҶ’        topic_forward_counts_[topic] += count;
734вҶ’      }
735вҶ’    }
736вҶ’  } catch (const std::exception& e) {
737вҶ’    spdlog::error("Error publishing aggregated messages: {}", e.what());
738вҶ’  }
739вҶ’}
