 39вҶ’// ---------------------------------------------------------------------------
 40вҶ’// MockMiddleware вҖ” in-process fake for unit-testing BridgeServer
 41вҶ’// ---------------------------------------------------------------------------
 42вҶ’class MockMiddleware : public MiddlewareInterface {
 43вҶ’ public:
 44вҶ’  // --- MiddlewareInterface overrides ---
 45вҶ’
 46вҶ’  tl::expected<void, std::string> initialize(uint16_t /*port*/) override {
 47вҶ’    ready_ = true;
 48вҶ’    return {};
 49вҶ’  }
 50вҶ’
 51вҶ’  void shutdown() override {
 52вҶ’    ready_ = false;
 53вҶ’  }
 54вҶ’
 55вҶ’  bool receive_request(std::vector<uint8_t>& data, std::string& client_identity) override {
 56вҶ’    std::lock_guard<std::mutex> lock(queue_mutex_);
 57вҶ’    if (request_queue_.empty()) {
 58вҶ’      return false;
 59вҶ’    }
 60вҶ’    auto& front = request_queue_.front();
 61вҶ’    client_identity = front.first;
 62вҶ’    data = std::move(front.second);
 63вҶ’    request_queue_.pop_front();
 64вҶ’    return true;
 65вҶ’  }
 66вҶ’
 67вҶ’  bool send_reply(const std::string& client_identity, const std::vector<uint8_t>& data) override {
 68вҶ’    std::lock_guard<std::mutex> lock(reply_mutex_);
 69вҶ’    replies_.emplace_back(client_identity, data);
 70вҶ’    return true;
 71вҶ’  }
 72вҶ’
 73вҶ’  bool publish_data(const std::vector<uint8_t>& /*data*/) override {
 74вҶ’    return true;
 75вҶ’  }
 76вҶ’
 77вҶ’  bool send_binary(const std::string& client_identity, const std::vector<uint8_t>& data) override {
 78вҶ’    std::lock_guard<std::mutex> lock(binary_mutex_);
 79вҶ’    binary_sends_.emplace_back(client_identity, data);
 80вҶ’    return true;
 81вҶ’  }
 82вҶ’
 83вҶ’  bool is_ready() const override {
 84вҶ’    return ready_;
 85вҶ’  }
 86вҶ’
 87вҶ’  void set_on_connect(ConnectionCallback callback) override {
 88вҶ’    std::lock_guard<std::mutex> lock(cb_mutex_);
 89вҶ’    on_connect_ = std::move(callback);
 90вҶ’  }
 91вҶ’
 92вҶ’  void set_on_disconnect(ConnectionCallback callback) override {
 93вҶ’    std::lock_guard<std::mutex> lock(cb_mutex_);
 94вҶ’    on_disconnect_ = std::move(callback);
 95вҶ’  }
 96вҶ’
 97вҶ’  // --- Test helpers ---
 98вҶ’
 99вҶ’  /// Push a text request as if it came from a connected client.
100вҶ’  void push_request(const std::string& client_id, const std::string& text) {
101вҶ’    std::lock_guard<std::mutex> lock(queue_mutex_);
102вҶ’    std::vector<uint8_t> data(text.begin(), text.end());
103вҶ’    request_queue_.emplace_back(client_id, std::move(data));
104вҶ’  }
105вҶ’
106вҶ’  /// Invoke the disconnect callback registered by BridgeServer.
107вҶ’  void simulate_disconnect(const std::string& client_id) {
108вҶ’    ConnectionCallback cb;
109вҶ’    {
110вҶ’      std::lock_guard<std::mutex> lock(cb_mutex_);
111вҶ’      cb = on_disconnect_;
112вҶ’    }
113вҶ’    if (cb) {
114вҶ’      cb(client_id);
115вҶ’    }
116вҶ’  }
117вҶ’
118вҶ’  /// Invoke the connect callback registered by BridgeServer.
119вҶ’  void simulate_connect(const std::string& client_id) {
120вҶ’    ConnectionCallback cb;
121вҶ’    {
122вҶ’      std::lock_guard<std::mutex> lock(cb_mutex_);
123вҶ’      cb = on_connect_;
124вҶ’    }
125вҶ’    if (cb) {
126вҶ’      cb(client_id);
127вҶ’    }
128вҶ’  }
129вҶ’
130вҶ’  /// Get the most recent reply sent to a given client (empty json on miss).
131вҶ’  json pop_reply(const std::string& client_id) {
132вҶ’    std::lock_guard<std::mutex> lock(reply_mutex_);
133вҶ’    for (auto it = replies_.rbegin(); it != replies_.rend(); ++it) {
134вҶ’      if (it->first == client_id) {
135вҶ’        std::string text(it->second.begin(), it->second.end());
136вҶ’        json j = json::parse(text, nullptr, false);
137вҶ’        replies_.erase(std::next(it).base());
138вҶ’        return j;
139вҶ’      }
140вҶ’    }
141вҶ’    return json{};
142вҶ’  }
143вҶ’
144вҶ’  /// Return all recorded binary sends (client_id, raw bytes).
145вҶ’  std::vector<std::pair<std::string, std::vector<uint8_t>>> get_binary_sends() {
146вҶ’    std::lock_guard<std::mutex> lock(binary_mutex_);
147вҶ’    return binary_sends_;
148вҶ’  }
149вҶ’
150вҶ’  void clear_binary_sends() {
151вҶ’    std::lock_guard<std::mutex> lock(binary_mutex_);
152вҶ’    binary_sends_.clear();
153вҶ’  }
154вҶ’
155вҶ’ private:
156вҶ’  bool ready_{false};
157вҶ’
158вҶ’  std::mutex queue_mutex_;
159вҶ’  std::deque<std::pair<std::string, std::vector<uint8_t>>> request_queue_;
160вҶ’
161вҶ’  std::mutex reply_mutex_;
162вҶ’  std::vector<std::pair<std::string, std::vector<uint8_t>>> replies_;
163вҶ’
164вҶ’  std::mutex binary_mutex_;
165вҶ’  std::vector<std::pair<std::string, std::vector<uint8_t>>> binary_sends_;
166вҶ’
167вҶ’  std::mutex cb_mutex_;
168вҶ’  ConnectionCallback on_connect_;
169вҶ’  ConnectionCallback on_disconnect_;
170вҶ’};
