206вҶ’class MockSubscriptionManager : public SubscriptionManagerInterface {
207вҶ’ public:
208вҶ’  void set_message_callback(MessageCallback callback) override {
209вҶ’    callback_ = std::move(callback);
210вҶ’  }
211вҶ’
212вҶ’  bool subscribe(const std::string& topic_name, const std::string& /*topic_type*/) override {
213вҶ’    // Simulate failure for non-existent topics (topics not in known set)
214вҶ’    if (known_topics_.find(topic_name) == known_topics_.end()) {
215вҶ’      return false;
216вҶ’    }
217вҶ’    subscribed_topics_.insert(topic_name);
218вҶ’    return true;
219вҶ’  }
220вҶ’
221вҶ’  bool unsubscribe(const std::string& topic_name) override {
222вҶ’    auto it = subscribed_topics_.find(topic_name);
223вҶ’    if (it == subscribed_topics_.end()) {
224вҶ’      return false;
225вҶ’    }
226вҶ’    subscribed_topics_.erase(it);
227вҶ’    return true;
228вҶ’  }
229вҶ’
230вҶ’  void unsubscribe_all() override {
231вҶ’    subscribed_topics_.clear();
232вҶ’  }
233вҶ’
234вҶ’  // Test helpers
235вҶ’  void add_known_topic(const std::string& topic_name) {
236вҶ’    known_topics_.insert(topic_name);
237вҶ’  }
238вҶ’
239вҶ’  bool is_subscribed(const std::string& topic_name) const {
240вҶ’    return subscribed_topics_.count(topic_name) > 0;
241вҶ’  }
242вҶ’
243вҶ’ private:
244вҶ’  MessageCallback callback_;
245вҶ’  std::set<std::string> known_topics_;
246вҶ’  std::set<std::string> subscribed_topics_;
247вҶ’};
