562вҶ’    mock_->push_request(id, hb.dump());
563вҶ’    server_->process_requests();
564вҶ’  }
565вҶ’  ASSERT_EQ(server_->get_active_session_count(), 3u);
566вҶ’
567вҶ’  // Call publish_aggregated_messages directly multiple times
