 59вҶ’bool BridgeServer::initialize() {
 60вҶ’  if (initialized_) {
 61вҶ’    spdlog::warn("Bridge server already initialized");
 62вҶ’    return true;
 63вҶ’  }
 64вҶ’
 65вҶ’  spdlog::info("Initializing bridge server...");
 66вҶ’
 67вҶ’  message_buffer_ = std::make_shared<MessageBuffer>();
 68вҶ’  session_manager_ = std::make_unique<SessionManager>(session_timeout_);
 69вҶ’
 70вҶ’  spdlog::info("Core components created");
 71вҶ’
 72вҶ’  // Set the global message callback to feed into message buffer
 73вҶ’  subscription_manager_->set_message_callback(
 74вҶ’      [this](const std::string& topic_name, std::shared_ptr<std::vector<std::byte>> cdr_data, uint64_t timestamp_ns) {
 75вҶ’        {
 76вҶ’          std::lock_guard<std::mutex> lock(stats_mutex_);
 77вҶ’          topic_receive_counts_[topic_name]++;
 78вҶ’        }
 79вҶ’        if (message_buffer_) {
 80вҶ’          message_buffer_->add_message(topic_name, timestamp_ns, std::move(cdr_data));
 81вҶ’        }
 82вҶ’      });
 83вҶ’
 84вҶ’  // Register disconnect callback before middleware init to avoid missing events
 85вҶ’  middleware_->set_on_disconnect([this](const std::string& client_id) {
 86вҶ’    spdlog::info("Client disconnected: '{}'", client_id);
 87вҶ’    cleanup_session(client_id);
 88вҶ’  });
 89вҶ’
 90вҶ’  // Initialize middleware (may start accepting connections immediately)
 91вҶ’  auto result = middleware_->initialize(static_cast<uint16_t>(port_));
 92вҶ’  if (!result) {
 93вҶ’    spdlog::error("Failed to initialize middleware: {}", result.error());
 94вҶ’    return false;
 95вҶ’  }
 96вҶ’  spdlog::info("Middleware initialized (port: {})", port_);
 97вҶ’
 98вҶ’  if (publish_rate_ <= 0.0) {
 99вҶ’    spdlog::error("Invalid publish_rate: {:.1f} (must be > 0)", publish_rate_);
100вҶ’    return false;
101вҶ’  }
102вҶ’
103вҶ’  initialized_ = true;
104вҶ’  spdlog::info("Bridge server initialization complete");
105вҶ’
106вҶ’  return true;
107вҶ’}
