29вҶ’void MessageBuffer::add_message(
30вҶ’    const std::string& topic_name, uint64_t timestamp_ns, std::shared_ptr<std::vector<std::byte>> data) {
31вҶ’  std::lock_guard<std::mutex> lock(mutex_);
32вҶ’
33вҶ’  cleanup_old_messages();
34вҶ’
35вҶ’  BufferedMessage msg;
36вҶ’  msg.timestamp_ns = timestamp_ns;
37вҶ’  msg.received_at_ns = get_current_time_ns();
38вҶ’  msg.data = std::move(data);
39вҶ’
40вҶ’  topic_buffers_[topic_name].push_back(std::move(msg));
41вҶ’}
