44вҶ’  std::lock_guard<std::mutex> lock(mutex_);
45вҶ’  out_messages = std::move(topic_buffers_);
46вҶ’  topic_buffers_.clear();
47вҶ’  last_read_timestamp_ns_ = get_current_time_ns();
48вҶ’}
