56вҶ’size_t MessageBuffer::size() const {
57вҶ’  std::lock_guard<std::mutex> lock(mutex_);
58вҶ’
59вҶ’  size_t total = 0;
60вҶ’  for (const auto& [topic, buffer] : topic_buffers_) {
61вҶ’    total += buffer.size();
62вҶ’  }
63вҶ’
64вҶ’  return total;
65вҶ’}
66вҶ’
67вҶ’void MessageBuffer::cleanup_old_messages() {
68вҶ’  uint64_t current_time = get_current_time_ns();
69вҶ’
70вҶ’  for (auto& [topic, buffer] : topic_buffers_) {
71вҶ’    while (!buffer.empty()) {
72вҶ’      const auto& oldest_msg = buffer.front();
73вҶ’      if (current_time - oldest_msg.received_at_ns > max_message_age_ns_) {
74вҶ’        buffer.pop_front();
75вҶ’      } else {
76вҶ’        break;
77вҶ’      }
78вҶ’    }
79вҶ’  }
80вҶ’
81вҶ’  for (auto it = topic_buffers_.begin(); it != topic_buffers_.end();) {
82вҶ’    if (it->second.empty()) {
83вҶ’      it = topic_buffers_.erase(it);
84вҶ’    } else {
85вҶ’      ++it;
86вҶ’    }
87вҶ’  }
88вҶ’}
