 29вҶ’#include "pj_bridge_ros2/ros2_topic_source.hpp"
 30вҶ’
 31вҶ’int main(int argc, char** argv) {
 32вҶ’  rclcpp::init(argc, argv);
 33вҶ’
 34вҶ’  auto node = std::make_shared<rclcpp::Node>("pj_bridge");
 35вҶ’
 36вҶ’  RCLCPP_INFO(node->get_logger(), "Starting pj_bridge (ROS2 backend)...");
 37вҶ’
 38вҶ’  // Declare and get parameters
 39вҶ’  node->declare_parameter<int>("port", 8080);
 40вҶ’  node->declare_parameter<double>("publish_rate", 50.0);
 41вҶ’  node->declare_parameter<double>("session_timeout", 10.0);
 42вҶ’  node->declare_parameter<bool>("strip_large_messages", true);
 43вҶ’
 44вҶ’  int port = node->get_parameter("port").as_int();
 45вҶ’  double publish_rate = node->get_parameter("publish_rate").as_double();
 46вҶ’  double session_timeout = node->get_parameter("session_timeout").as_double();
 47вҶ’  bool strip_large_messages = node->get_parameter("strip_large_messages").as_bool();
 48вҶ’
 49вҶ’  RCLCPP_INFO(
 50вҶ’      node->get_logger(),
 51вҶ’      "Configuration: port=%d, publish_rate=%.1f Hz, session_timeout=%.1f s, strip_large_messages=%s", port,
 52вҶ’      publish_rate, session_timeout, strip_large_messages ? "true" : "false");
 53вҶ’
 54вҶ’  try {
 55вҶ’    // Create backend components
 56вҶ’    auto topic_source = std::make_shared<pj_bridge::Ros2TopicSource>(node);
 57вҶ’    auto sub_manager = std::make_shared<pj_bridge::Ros2SubscriptionManager>(node, strip_large_messages);
 58вҶ’    auto middleware = std::make_shared<pj_bridge::WebSocketMiddleware>();
 59вҶ’
 60вҶ’    // Create bridge server
 61вҶ’    pj_bridge::BridgeServer server(topic_source, sub_manager, middleware, port, session_timeout, publish_rate);
 62вҶ’
 63вҶ’    if (!server.initialize()) {
 64вҶ’      RCLCPP_ERROR(node->get_logger(), "Failed to initialize bridge server");
 65вҶ’      rclcpp::shutdown();
 66вҶ’      return 1;
 67вҶ’    }
 68вҶ’
 69вҶ’    RCLCPP_INFO(node->get_logger(), "Bridge server initialized successfully");
 70вҶ’    RCLCPP_INFO(node->get_logger(), "Ready to accept WebSocket connections on port %d", port);
 71вҶ’
 72вҶ’    // ROS2 timers drive the event loop
 73вҶ’    using namespace std::chrono_literals;
 74вҶ’
 75вҶ’    auto request_timer = node->create_wall_timer(10ms, [&server]() { server.process_requests(); });
 76вҶ’
 77вҶ’    auto publish_period = std::chrono::duration<double>(1.0 / publish_rate);
 78вҶ’    auto publish_timer =
 79вҶ’        node->create_wall_timer(std::chrono::duration_cast<std::chrono::nanoseconds>(publish_period),
 80вҶ’                                [&server]() { server.publish_aggregated_messages(); });
 81вҶ’
 82вҶ’    auto timeout_timer = node->create_wall_timer(1s, [&server]() { server.check_session_timeouts(); });
 83вҶ’
 84вҶ’    // Spin until shutdown
 85вҶ’    rclcpp::executors::SingleThreadedExecutor executor;
 86вҶ’    executor.add_node(node);
 87вҶ’
 88вҶ’    while (rclcpp::ok()) {
 89вҶ’      executor.spin_some(100ms);
 90вҶ’    }
 91вҶ’
 92вҶ’    // Graceful shutdown
 93вҶ’    RCLCPP_INFO(node->get_logger(), "Shutting down bridge server...");
 94вҶ’
 95вҶ’    request_timer->cancel();
 96вҶ’    publish_timer->cancel();
 97вҶ’    timeout_timer->cancel();
 98вҶ’    executor.remove_node(node);
 99вҶ’
100вҶ’    // Clear the subscription manager callback before server destruction
101вҶ’    sub_manager->set_message_callback(nullptr);
102вҶ’    sub_manager->unsubscribe_all();
103вҶ’
104вҶ’    auto [total_messages, total_bytes] = server.get_publish_stats();
105вҶ’    RCLCPP_INFO(
106вҶ’        node->get_logger(), "Final statistics: %lu messages published, %lu bytes transmitted", total_messages,
107вҶ’        total_bytes);
108вҶ’
109вҶ’    RCLCPP_INFO(node->get_logger(), "Bridge server shutdown complete");
110вҶ’
111вҶ’  } catch (const std::exception& e) {
112вҶ’    RCLCPP_ERROR(node->get_logger(), "Exception in main: %s", e.what());
113вҶ’    rclcpp::shutdown();
114вҶ’    return 1;
115вҶ’  }
116вҶ’
117вҶ’  rclcpp::shutdown();
118вҶ’  return 0;
119вҶ’}
