179вҶ’    spdlog::info("Created new session for client '{}'", client_id);
180вҶ’  }
181вҶ’
182вҶ’  session_manager_->update_heartbeat(client_id);
183вҶ’
184вҶ’  auto topics = topic_source_->get_topics();
185вҶ’
186вҶ’  json response;
187вҶ’  response["status"] = "success";
188вҶ’  response["topics"] = json::array();
189вҶ’
190вҶ’  for (const auto& topic : topics) {
191вҶ’    json topic_entry;
192вҶ’    topic_entry["name"] = topic.name;
193вҶ’    topic_entry["type"] = topic.type;
194вҶ’    response["topics"].push_back(topic_entry);
