204вҶ’std::string BridgeServer::handle_subscribe(const std::string& client_id, const nlohmann::json& request) {
205вҶ’  if (!session_manager_->session_exists(client_id)) {
206вҶ’    session_manager_->create_session(client_id);
207вҶ’    spdlog::info("Created new session for client '{}'", client_id);
208вҶ’  }
209вҶ’
210вҶ’  session_manager_->update_heartbeat(client_id);
211вҶ’
212вҶ’  if (!request.contains("topics")) {
213вҶ’    return create_error_response("INVALID_REQUEST", "Missing 'topics' field", request);
214вҶ’  }
215вҶ’
216вҶ’  if (!request["topics"].is_array()) {
217вҶ’    return create_error_response("INVALID_REQUEST", "'topics' must be an array", request);
218вҶ’  }
219вҶ’
220вҶ’  auto current_subs = session_manager_->get_subscriptions(client_id);
221вҶ’
222вҶ’  // Parse requested topics вҖ” supports mixed array of strings and objects:
223вҶ’  //   ["topic1", {"name": "topic2", "max_rate_hz": 10.0}]
224вҶ’  std::unordered_map<std::string, double> requested_topics;
225вҶ’  for (const auto& topic : request["topics"]) {
226вҶ’    if (topic.is_string()) {
227вҶ’      requested_topics[topic.get<std::string>()] = 0.0;
228вҶ’    } else if (topic.is_object() && topic.contains("name") && topic["name"].is_string()) {
229вҶ’      double rate_hz = 0.0;
230вҶ’      if (topic.contains("max_rate_hz") && topic["max_rate_hz"].is_number()) {
231вҶ’        rate_hz = topic["max_rate_hz"].get<double>();
232вҶ’        if (rate_hz < 0.0) {
233вҶ’          rate_hz = 0.0;
234вҶ’        }
235вҶ’      }
236вҶ’      requested_topics[topic["name"].get<std::string>()] = rate_hz;
237вҶ’    }
238вҶ’  }
239вҶ’
240вҶ’  // Determine which topics to add (additive model вҖ” subscribe only adds, never removes)
241вҶ’  std::vector<std::string> topics_to_add;
242вҶ’  for (const auto& [topic, rate] : requested_topics) {
243вҶ’    if (current_subs.find(topic) == current_subs.end()) {
244вҶ’      topics_to_add.push_back(topic);
245вҶ’    }
246вҶ’  }
247вҶ’
248вҶ’  // Build topic name вҶ’ type lookup from topic source
249вҶ’  auto available_topics = topic_source_->get_topics();
250вҶ’  std::unordered_map<std::string, std::string> topic_types;
251вҶ’  for (const auto& topic : available_topics) {
252вҶ’    topic_types[topic.name] = topic.type;
253вҶ’  }
254вҶ’
255вҶ’  // Subscribe to new topics вҖ” track successes and failures
256вҶ’  json schemas = json::object();
257вҶ’  json failures = json::array();
258вҶ’  std::unordered_set<std::string> successfully_subscribed;
259вҶ’
260вҶ’  for (const auto& topic_name : topics_to_add) {
261вҶ’    if (topic_types.find(topic_name) == topic_types.end()) {
262вҶ’      spdlog::warn("Client '{}' requested non-existent topic '{}'", client_id, topic_name);
263вҶ’      json failure;
264вҶ’      failure["topic"] = topic_name;
265вҶ’      failure["reason"] = "Topic does not exist";
266вҶ’      failures.push_back(failure);
267вҶ’      continue;
268вҶ’    }
269вҶ’
270вҶ’    std::string topic_type = topic_types[topic_name];
271вҶ’
272вҶ’    // Get schema BEFORE subscribing to avoid corrupting the reference count
273вҶ’    // if schema extraction fails after subscribe() increments it.
274вҶ’    std::string schema;
275вҶ’    try {
276вҶ’      schema = topic_source_->get_schema(topic_name);
277вҶ’    } catch (const std::exception& e) {
278вҶ’      spdlog::error("Failed to get schema for topic '{}': {}", topic_name, e.what());
279вҶ’      json failure;
280вҶ’      failure["topic"] = topic_name;
281вҶ’      failure["reason"] = std::string("Schema extraction failed: ") + e.what();
282вҶ’      failures.push_back(failure);
283вҶ’      continue;
284вҶ’    }
285вҶ’
286вҶ’    if (schema.empty()) {
287вҶ’      spdlog::error("Empty schema for topic '{}' (type: {})", topic_name, topic_type);
288вҶ’      json failure;
289вҶ’      failure["topic"] = topic_name;
290вҶ’      failure["reason"] = "Schema extraction returned empty definition";
291вҶ’      failures.push_back(failure);
292вҶ’      continue;
293вҶ’    }
294вҶ’
295вҶ’    // Subscribe via subscription manager (ref-counted)
296вҶ’    bool success = subscription_manager_->subscribe(topic_name, topic_type);
297вҶ’    if (!success) {
298вҶ’      spdlog::error("Failed to subscribe to topic '{}'", topic_name);
299вҶ’      json failure;
300вҶ’      failure["topic"] = topic_name;
301вҶ’      failure["reason"] = "Subscription manager failed to create subscription";
302вҶ’      failures.push_back(failure);
303вҶ’      continue;
304вҶ’    }
305вҶ’
306вҶ’    nlohmann::json schema_obj;
307вҶ’    schema_obj["encoding"] = topic_source_->schema_encoding();
308вҶ’    schema_obj["definition"] = schema;
309вҶ’    schemas[topic_name] = schema_obj;
310вҶ’    successfully_subscribed.insert(topic_name);
311вҶ’
312вҶ’    spdlog::info("Client '{}' subscribed to topic '{}' (type: {})", client_id, topic_name, topic_type);
313вҶ’  }
314вҶ’
315вҶ’  // Update session subscriptions with successfully subscribed topics (additive model)
316вҶ’  std::unordered_map<std::string, double> final_subscriptions = current_subs;
317вҶ’  for (const auto& topic : successfully_subscribed) {
318вҶ’    final_subscriptions[topic] = requested_topics[topic];
319вҶ’  }
320вҶ’  // Update rates for topics that were already subscribed but may have a new rate
321вҶ’  for (const auto& [topic, rate] : requested_topics) {
322вҶ’    if (final_subscriptions.find(topic) != final_subscriptions.end()) {
323вҶ’      final_subscriptions[topic] = rate;
324вҶ’    }
325вҶ’  }
326вҶ’  session_manager_->update_subscriptions(client_id, final_subscriptions);
327вҶ’
328вҶ’  // Build response
329вҶ’  json response;
330вҶ’  if (failures.empty()) {
331вҶ’    response["status"] = "success";
332вҶ’  } else if (schemas.empty()) {
333вҶ’    response["status"] = "error";
334вҶ’    response["error_code"] = "ALL_SUBSCRIPTIONS_FAILED";
335вҶ’    response["message"] = "Failed to subscribe to all requested topics";
336вҶ’  } else {
337вҶ’    response["status"] = "partial_success";
338вҶ’    response["message"] = "Some subscriptions failed";
339вҶ’  }
340вҶ’
341вҶ’  response["schemas"] = schemas;
342вҶ’  if (!failures.empty()) {
343вҶ’    response["failures"] = failures;
344вҶ’  }
345вҶ’
346вҶ’  // Include rate limits in response for topics with non-zero rates
347вҶ’  json rate_limits = json::object();
348вҶ’  for (const auto& [topic, rate] : final_subscriptions) {
349вҶ’    if (rate > 0.0) {
350вҶ’      rate_limits[topic] = rate;
351вҶ’    }
352вҶ’  }
353вҶ’  if (!rate_limits.empty()) {
354вҶ’    response["rate_limits"] = rate_limits;
355вҶ’  }
356вҶ’
357вҶ’  inject_response_fields(response, request);
358вҶ’
359вҶ’  return response.dump();
