1207вҶ’// ---------------------------------------------------------------------------
1208вҶ’// PausedClientDoesNotReceiveBinaryFrames
1209вҶ’//
1210вҶ’// Tests that paused clients are skipped when publishing binary frames.
1211вҶ’// Since we can't easily inject messages into the buffer, we verify the
1212вҶ’// paused state is respected by checking that a paused client with a
1213вҶ’// subscription group is skipped.
1214вҶ’// ---------------------------------------------------------------------------
1215вҶ’TEST_F(BridgeServerTest, PausedClientDoesNotReceiveBinaryFrames) {
1216вҶ’  ASSERT_TRUE(server_->initialize());
1217вҶ’
1218вҶ’  // Create two sessions via heartbeats
1219вҶ’  json hb;
1220вҶ’  hb["command"] = "heartbeat";
1221вҶ’  mock_->push_request("client_paused_1", hb.dump());
1222вҶ’  server_->process_requests();
1223вҶ’  mock_->push_request("client_active_1", hb.dump());
1224вҶ’  server_->process_requests();
1225вҶ’  ASSERT_EQ(server_->get_active_session_count(), 2u);
1226вҶ’
1227вҶ’  // Subscribe both clients to the same non-existent topic
1228вҶ’  // (subscription will fail but session subscription intent is tracked)
1229вҶ’  json sub_req;
1230вҶ’  sub_req["command"] = "subscribe";
1231вҶ’  sub_req["topics"] = json::array({"/test_topic"});
1232вҶ’  mock_->push_request("client_paused_1", sub_req.dump());
1233вҶ’  server_->process_requests();
1234вҶ’  mock_->pop_reply("client_paused_1");  // discard
1235вҶ’
1236вҶ’  mock_->push_request("client_active_1", sub_req.dump());
1237вҶ’  server_->process_requests();
1238вҶ’  mock_->pop_reply("client_active_1");  // discard
1239вҶ’
1240вҶ’  // Pause client_paused_1
1241вҶ’  json pause_req;
1242вҶ’  pause_req["command"] = "pause";
1243вҶ’  mock_->push_request("client_paused_1", pause_req.dump());
1244вҶ’  server_->process_requests();
1245вҶ’
1246вҶ’  json pause_response = mock_->pop_reply("client_paused_1");
1247вҶ’  ASSERT_FALSE(pause_response.is_discarded());
1248вҶ’  EXPECT_TRUE(pause_response["paused"].get<bool>());
1249вҶ’
1250вҶ’  // Clear any binary sends from previous operations
1251вҶ’  mock_->clear_binary_sends();
1252вҶ’
1253вҶ’  // Call publish_aggregated_messages directly
1254вҶ’  for (int i = 0; i < 3; ++i) {
1255вҶ’    server_->publish_aggregated_messages();
1256вҶ’  }
1257вҶ’
1258вҶ’  // Verify binary sends - since topics don't exist, no messages are buffered
1259вҶ’  // so no binary sends should occur. But if messages were buffered,
1260вҶ’  // only client_active_1 would receive them, not client_paused_1.
1261вҶ’  auto binary_sends = mock_->get_binary_sends();
1262вҶ’  for (const auto& [client_id, data] : binary_sends) {
1263вҶ’    // If any binary sends occurred, they should NOT be to the paused client
1264вҶ’    EXPECT_NE(client_id, "client_paused_1") << "Paused client should not receive binary frames";
1265вҶ’  }
1266вҶ’}
