1311вҶ’// ===========================================================================
1312вҶ’// REGRESSION TESTS - Critical bugs found in code review
1313вҶ’// ===========================================================================
1314вҶ’
1315вҶ’// ---------------------------------------------------------------------------
1316вҶ’// RegressionTest_BinaryFrameIncludesHeader
1317вҶ’//
1318вҶ’// Regression test for bug: finalize() not called in publish_aggregated_messages().
1319вҶ’// Binary frames MUST include the 16-byte header with magic "PJRB" (0x42524A50).
1320вҶ’// Without this fix, compress_zstd() was called directly, skipping the header.
1321вҶ’// ---------------------------------------------------------------------------
1322вҶ’TEST_F(BridgeServerTest, RegressionTest_BinaryFrameIncludesHeader) {
1323вҶ’  // This test verifies that when binary data is sent, it includes the
1324вҶ’  // 16-byte header with magic bytes "PJRB" at the start.
1325вҶ’  //
1326вҶ’  // The bug was: publish_aggregated_messages() called compress_zstd() directly
1327вҶ’  // instead of finalize(), so the header was never prepended.
1328вҶ’
1329вҶ’  // We can't easily trigger actual message publishing in unit tests without
1330вҶ’  // real topics, but we can verify the serializer's finalize() method
1331вҶ’  // is correctly producing the header format by checking the protocol constants.
1332вҶ’
1333вҶ’  // Verify the expected magic value matches "PJRB" in little-endian
1334вҶ’  constexpr uint32_t expected_magic = 0x42524A50;  // "PJRB"
1335вҶ’  const char* magic_bytes = reinterpret_cast<const char*>(&expected_magic);
1336вҶ’  EXPECT_EQ(magic_bytes[0], 'P');
1337вҶ’  EXPECT_EQ(magic_bytes[1], 'J');
1338вҶ’  EXPECT_EQ(magic_bytes[2], 'R');
1339вҶ’  EXPECT_EQ(magic_bytes[3], 'B');
1340вҶ’
1341вҶ’  // Note: The actual integration test that binary frames sent to clients
1342вҶ’  // include this header is covered by the message_serializer tests
1343вҶ’  // (FinalizeIncludesBinaryHeader, HeaderMagicIsPJRB) which verify finalize()
1344вҶ’  // produces correct output. This test documents the regression.
1345вҶ’}
1346вҶ’
1347вҶ’// ---------------------------------------------------------------------------
1348вҶ’// RegressionTest_PausedClientDisconnectNoDoubleDecrement
1349вҶ’//
1350вҶ’// Regression test for bug: double-decrement of subscription ref counts when
1351вҶ’// a paused client disconnects.
1352вҶ’//
1353вҶ’// The bug was: handle_pause() decremented ref counts, then cleanup_session()
1354вҶ’// also decremented them again on disconnect, causing ref count corruption.
1355вҶ’//
1356вҶ’// Fix: cleanup_session() now checks if client was paused before unsubscribing.
1357вҶ’// ---------------------------------------------------------------------------
1358вҶ’TEST_F(BridgeServerTest, RegressionTest_PausedClientDisconnectNoDoubleDecrement) {
1359вҶ’  ASSERT_TRUE(server_->initialize());
1360вҶ’
1361вҶ’  // Client 1: Create session, pause, then disconnect
1362вҶ’  // This tests the core fix: cleanup_session should not unsubscribe if paused
1363вҶ’  const std::string client1 = "client_paused_disconnect";
1364вҶ’
1365вҶ’  // Create session
1366вҶ’  json hb;
1367вҶ’  hb["command"] = "heartbeat";
1368вҶ’  mock_->push_request(client1, hb.dump());
1369вҶ’  server_->process_requests();
1370вҶ’  mock_->pop_reply(client1);  // discard
1371вҶ’  EXPECT_EQ(server_->get_active_session_count(), 1u);
1372вҶ’
1373вҶ’  // Pause client1
1374вҶ’  json pause_req;
1375вҶ’  pause_req["command"] = "pause";
1376вҶ’  mock_->push_request(client1, pause_req.dump());
1377вҶ’  server_->process_requests();
1378вҶ’  json pause_resp = mock_->pop_reply(client1);
1379вҶ’  EXPECT_TRUE(pause_resp["paused"].get<bool>());
1380вҶ’
1381вҶ’  // Simulate disconnect while paused
1382вҶ’  // Before the fix, cleanup_session would try to unsubscribe even though
1383вҶ’  // pause already decremented ref counts, causing double-decrement
1384вҶ’  mock_->simulate_disconnect(client1);
1385вҶ’
1386вҶ’  // Verify session was cleaned up without crash or error
1387вҶ’  EXPECT_EQ(server_->get_active_session_count(), 0u);
1388вҶ’
1389вҶ’  // Client 2: Create a new session after the paused disconnect
1390вҶ’  // This verifies the system is still in a good state
1391вҶ’  const std::string client2 = "client_after_paused_disconnect";
1392вҶ’
1393вҶ’  mock_->push_request(client2, hb.dump());
1394вҶ’  server_->process_requests();
1395вҶ’  json hb_resp = mock_->pop_reply(client2);
1396вҶ’
1397вҶ’  // Heartbeat should succeed - system is healthy
1398вҶ’  EXPECT_EQ(hb_resp["status"], "ok");
1399вҶ’  EXPECT_EQ(server_->get_active_session_count(), 1u);
1400вҶ’
1401вҶ’  // Clean disconnect of client2
1402вҶ’  mock_->simulate_disconnect(client2);
1403вҶ’  EXPECT_EQ(server_->get_active_session_count(), 0u);
1404вҶ’}
1405вҶ’
1406вҶ’// ---------------------------------------------------------------------------
1407вҶ’// Regression: Subscribe to a topic that exists but has an empty schema should
1408вҶ’// report a failure (not silently succeed with an empty definition).
1409вҶ’//
1410вҶ’// In the unit test environment, we can't easily mock SchemaExtractor, but we
1411вҶ’// can verify the failure-reporting path by subscribing to a non-existent topic
1412вҶ’// which produces the failure, confirming the failure response structure is correct.
1413вҶ’// ---------------------------------------------------------------------------
1414вҶ’TEST_F(BridgeServerTest, SubscribeFailureResponseContainsTopicAndReason) {
1415вҶ’  ASSERT_TRUE(server_->initialize());
1416вҶ’
1417вҶ’  json req;
1418вҶ’  req["command"] = "subscribe";
1419вҶ’  req["topics"] = json::array({"/nonexistent_topic_1", "/nonexistent_topic_2"});
1420вҶ’  mock_->push_request("client_fail_multi", req.dump());
1421вҶ’  server_->process_requests();
1422вҶ’
1423вҶ’  json reply = mock_->pop_reply("client_fail_multi");
1424вҶ’  ASSERT_FALSE(reply.is_discarded());
1425вҶ’  EXPECT_EQ(reply["status"], "error");
1426вҶ’  EXPECT_EQ(reply["error_code"], "ALL_SUBSCRIPTIONS_FAILED");
1427вҶ’  ASSERT_TRUE(reply.contains("failures"));
1428вҶ’  ASSERT_EQ(reply["failures"].size(), 2u);
1429вҶ’
1430вҶ’  // Each failure entry must have topic and reason
1431вҶ’  for (const auto& failure : reply["failures"]) {
1432вҶ’    EXPECT_TRUE(failure.contains("topic"));
1433вҶ’    EXPECT_TRUE(failure.contains("reason"));
1434вҶ’    EXPECT_FALSE(failure["topic"].get<std::string>().empty());
1435вҶ’    EXPECT_FALSE(failure["reason"].get<std::string>().empty());
1436вҶ’  }
1437вҶ’}
