26вҶ’MessageBuffer::MessageBuffer(uint64_t max_message_age_ns)
27вҶ’    : last_read_timestamp_ns_(get_current_time_ns()), max_message_age_ns_(max_message_age_ns) {}
28вҶ’
29вҶ’void MessageBuffer::add_message(
30вҶ’    const std::string& topic_name, uint64_t timestamp_ns, std::shared_ptr<std::vector<std::byte>> data) {
31вҶ’  std::lock_guard<std::mutex> lock(mutex_);
32вҶ’
33вҶ’  cleanup_old_messages();
34вҶ’
35вҶ’  BufferedMessage msg;
36вҶ’  msg.timestamp_ns = timestamp_ns;
37вҶ’  msg.received_at_ns = get_current_time_ns();
38вҶ’  msg.data = std::move(data);
39вҶ’
40вҶ’  topic_buffers_[topic_name].push_back(std::move(msg));
41вҶ’}
42вҶ’
43вҶ’void MessageBuffer::move_messages(std::unordered_map<std::string, std::deque<BufferedMessage>>& out_messages) {
44вҶ’  std::lock_guard<std::mutex> lock(mutex_);
45вҶ’  out_messages = std::move(topic_buffers_);
46вҶ’  topic_buffers_.clear();
47вҶ’  last_read_timestamp_ns_ = get_current_time_ns();
48вҶ’}
49вҶ’
50вҶ’void MessageBuffer::clear() {
51вҶ’  std::lock_guard<std::mutex> lock(mutex_);
52вҶ’  topic_buffers_.clear();
53вҶ’  last_read_timestamp_ns_ = get_current_time_ns();
54вҶ’}
55вҶ’
56вҶ’size_t MessageBuffer::size() const {
57вҶ’  std::lock_guard<std::mutex> lock(mutex_);
58вҶ’
59вҶ’  size_t total = 0;
60вҶ’  for (const auto& [topic, buffer] : topic_buffers_) {
61вҶ’    total += buffer.size();
62вҶ’  }
63вҶ’
64вҶ’  return total;
65вҶ’}
66вҶ’
67вҶ’void MessageBuffer::cleanup_old_messages() {
68вҶ’  uint64_t current_time = get_current_time_ns();
69вҶ’
70вҶ’  for (auto& [topic, buffer] : topic_buffers_) {
71вҶ’    while (!buffer.empty()) {
72вҶ’      const auto& oldest_msg = buffer.front();
73вҶ’      if (current_time - oldest_msg.received_at_ns > max_message_age_ns_) {
74вҶ’        buffer.pop_front();
75вҶ’      } else {
76вҶ’        break;
77вҶ’      }
78вҶ’    }
79вҶ’  }
80вҶ’
81вҶ’  for (auto it = topic_buffers_.begin(); it != topic_buffers_.end();) {
82вҶ’    if (it->second.empty()) {
83вҶ’      it = topic_buffers_.erase(it);
84вҶ’    } else {
85вҶ’      ++it;
86вҶ’    }
87вҶ’  }
88вҶ’}
