 51вҶ’  double session_timeout = 10.0;
 52вҶ’  std::string qos_profile;
 53вҶ’  std::string log_level = "info";
 54вҶ’  bool stats_enabled = false;
 55вҶ’
 56вҶ’  app.add_option("--domains,-d", domain_ids, "DDS domain IDs")->required()->expected(1, -1);
 57вҶ’  app.add_option("--port,-p", port, "WebSocket port")->default_val(8080)->check(CLI::Range(1, 65535));
 58вҶ’  app.add_option("--publish-rate", publish_rate, "Aggregation publish rate in Hz")->default_val(50.0);
 59вҶ’  app.add_option("--session-timeout", session_timeout, "Session timeout in seconds")->default_val(10.0);
 60вҶ’  app.add_option("--qos-profile", qos_profile, "QoS profile XML file path");
 61вҶ’  app.add_option("--log-level", log_level, "Log level (trace, debug, info, warn, error)")->default_val("info");
 62вҶ’  app.add_flag("--stats", stats_enabled, "Print statistics every 5 seconds");
 63вҶ’
 64вҶ’  CLI11_PARSE(app, argc, argv);
 65вҶ’
 66вҶ’  spdlog::set_level(spdlog::level::from_str(log_level));
 67вҶ’
 68вҶ’  spdlog::info("pj_bridge (RTI DDS backend) starting...");
 69вҶ’  spdlog::info("  Domains: {}", fmt::join(domain_ids, ", "));
 70вҶ’  spdlog::info("  Port: {}", port);
 71вҶ’  spdlog::info("  Publish rate: {:.1f} Hz", publish_rate);
 72вҶ’  spdlog::info("  Session timeout: {:.1f} s", session_timeout);
 73вҶ’  if (!qos_profile.empty()) {
 74вҶ’    spdlog::info("  QoS profile: {}", qos_profile);
 75вҶ’  }
 76вҶ’
 77вҶ’  std::signal(SIGINT, signal_handler);
 78вҶ’  std::signal(SIGTERM, signal_handler);
 79вҶ’
 80вҶ’  try {
 81вҶ’    // Create DDS components
 82вҶ’    pj_bridge::DdsTopicDiscovery discovery(domain_ids, qos_profile);
 83вҶ’    pj_bridge::DdsSubscriptionManager subscriptions(discovery);
 84вҶ’
 85вҶ’    // Create adapters
 86вҶ’    auto topic_source = std::make_shared<pj_bridge::RtiTopicSource>(discovery);
 87вҶ’    auto sub_manager = std::make_shared<pj_bridge::RtiSubscriptionManager>(subscriptions);
 88вҶ’
 89вҶ’    // Create WebSocket middleware
 90вҶ’    auto middleware = std::make_shared<pj_bridge::WebSocketMiddleware>();
 91вҶ’
 92вҶ’    // Create bridge server
 93вҶ’    pj_bridge::BridgeServer server(topic_source, sub_manager, middleware, port, session_timeout, publish_rate);
 94вҶ’
 95вҶ’    if (!server.initialize()) {
 96вҶ’      spdlog::error("Failed to initialize bridge server");
 97вҶ’      return 1;
 98вҶ’    }
 99вҶ’
100вҶ’    spdlog::info("Bridge server initialized, entering event loop");
101вҶ’
102вҶ’    // Event loop
103вҶ’    using clock = std::chrono::steady_clock;
104вҶ’    auto publish_interval =
105вҶ’        std::chrono::duration_cast<std::chrono::nanoseconds>(std::chrono::duration<double>(1.0 / publish_rate));
106вҶ’    auto last_publish = clock::now();
107вҶ’    auto last_timeout_check = clock::now();
108вҶ’    auto last_stats_print = clock::now();
109вҶ’    uint64_t prev_bytes_published = 0;
110вҶ’
111вҶ’    while (!g_shutdown.load()) {
112вҶ’      server.process_requests();
113вҶ’
114вҶ’      auto now = clock::now();
115вҶ’
116вҶ’      if (now - last_publish >= publish_interval) {
117вҶ’        server.publish_aggregated_messages();
118вҶ’        last_publish += publish_interval;
119вҶ’      }
120вҶ’
121вҶ’      if (now - last_timeout_check >= std::chrono::seconds(1)) {
122вҶ’        server.check_session_timeouts();
123вҶ’        last_timeout_check = now;
124вҶ’      }
125вҶ’
126вҶ’      if (stats_enabled && now - last_stats_print >= std::chrono::seconds(5)) {
127вҶ’        auto elapsed = std::chrono::duration<double>(now - last_stats_print).count();
128вҶ’        auto snapshot = server.snapshot_and_reset_stats();
129вҶ’
130вҶ’        std::string stats_msg = "=== Stats ===\n  DDS receive rates:";
