135вҶ’            stats_msg += fmt::format("\n    {}: {:.1f} msg/s", topic, static_cast<double>(count) / elapsed);
136вҶ’          }
137вҶ’        }
138вҶ’
139вҶ’        stats_msg +=
140вҶ’            fmt::format("\n  Publish frequency: {:.1f} Hz", static_cast<double>(snapshot.publish_cycles) / elapsed);
141вҶ’        uint64_t delta_bytes = snapshot.total_bytes_published - prev_bytes_published;
142вҶ’        prev_bytes_published = snapshot.total_bytes_published;
143вҶ’        stats_msg +=
144вҶ’            fmt::format("\n  Sent: {:.2f} MB/s", static_cast<double>(delta_bytes) / elapsed / (1024.0 * 1024.0));
145вҶ’
146вҶ’        spdlog::info(stats_msg);
147вҶ’        last_stats_print = now;
148вҶ’      }
149вҶ’
150вҶ’      std::this_thread::sleep_for(std::chrono::milliseconds(1));
151вҶ’    }
152вҶ’
153вҶ’    spdlog::info("Shutting down...");
154вҶ’
155вҶ’    // Explicit ordered shutdown to avoid use-after-free:
156вҶ’    // 1. Clear DDS message callback
157вҶ’    spdlog::debug("[shutdown] Clearing DDS message callback...");
158вҶ’    subscriptions.set_message_callback(nullptr);
159вҶ’    // 2. Unsubscribe all DDS readers
160вҶ’    spdlog::debug("[shutdown] Unsubscribing all DDS readers...");
161вҶ’    subscriptions.unsubscribe_all();
162вҶ’    // 3. Shutdown WebSocket server
163вҶ’    spdlog::debug("[shutdown] Shutting down WebSocket middleware...");
164вҶ’    middleware->shutdown();
165вҶ’    spdlog::debug("[shutdown] Cleanup complete, exiting scope (destructors will run)...");
166вҶ’  } catch (const std::exception& e) {
167вҶ’    spdlog::error("Fatal error: {}", e.what());
168вҶ’    return 1;
169вҶ’  }
170вҶ’
171вҶ’  return 0;
172вҶ’}
