271вҶ’TEST_F(MessageBufferTest, ThreadSafety) {
272вҶ’  std::vector<uint8_t> data = {1, 2, 3};
273вҶ’  const int num_threads = 10;
274вҶ’  const int messages_per_thread = 100;
275вҶ’
276вҶ’  std::vector<std::thread> threads;
277вҶ’  uint64_t current_time_ns = get_current_time_ns();
278вҶ’
279вҶ’  // Multiple threads adding messages
280вҶ’  for (int i = 0; i < num_threads; ++i) {
281вҶ’    threads.emplace_back([this, &data, i, messages_per_thread, current_time_ns]() {
282вҶ’      for (int j = 0; j < messages_per_thread; ++j) {
283вҶ’        std::string topic_name = "topic" + std::to_string(i);
284вҶ’        buffer_.add_message(topic_name, current_time_ns + j, create_test_data(data));
285вҶ’      }
286вҶ’    });
287вҶ’  }
288вҶ’
289вҶ’  // One thread moving messages
290вҶ’  std::atomic<int> total_moved{0};
291вҶ’  threads.emplace_back([this, &total_moved]() {
292вҶ’    for (int i = 0; i < 10; ++i) {
293вҶ’      std::unordered_map<std::string, std::deque<BufferedMessage>> messages;
294вҶ’      buffer_.move_messages(messages);
295вҶ’      for (const auto& [topic, msgs] : messages) {
296вҶ’        total_moved += msgs.size();
297вҶ’      }
298вҶ’      std::this_thread::sleep_for(std::chrono::milliseconds(10));
299вҶ’    }
300вҶ’  });
301вҶ’
302вҶ’  for (auto& t : threads) {
303вҶ’    t.join();
304вҶ’  }
305вҶ’
306вҶ’  // Get any remaining messages
307вҶ’  std::unordered_map<std::string, std::deque<BufferedMessage>> final_messages;
308вҶ’  buffer_.move_messages(final_messages);
309вҶ’  for (const auto& [topic, msgs] : final_messages) {
310вҶ’    total_moved += msgs.size();
311вҶ’  }
312вҶ’
313вҶ’  // All messages should be accounted for
314вҶ’  EXPECT_EQ(total_moved.load(), num_threads * messages_per_thread);
315вҶ’}
