 92вҶ’  void set_on_disconnect(ConnectionCallback callback) override {
 93вҶ’    std::lock_guard<std::mutex> lock(cb_mutex_);
 94вҶ’    on_disconnect_ = std::move(callback);
 95вҶ’  }
 96вҶ’
 97вҶ’  // --- Test helpers ---
 98вҶ’
 99вҶ’  /// Push a text request as if it came from a connected client.
100вҶ’  void push_request(const std::string& client_id, const std::string& text) {
101вҶ’    std::lock_guard<std::mutex> lock(queue_mutex_);
102вҶ’    std::vector<uint8_t> data(text.begin(), text.end());
103вҶ’    request_queue_.emplace_back(client_id, std::move(data));
104вҶ’  }
105вҶ’
106вҶ’  /// Invoke the disconnect callback registered by BridgeServer.
107вҶ’  void simulate_disconnect(const std::string& client_id) {
108вҶ’    ConnectionCallback cb;
109вҶ’    {
110вҶ’      std::lock_guard<std::mutex> lock(cb_mutex_);
111вҶ’      cb = on_disconnect_;
112вҶ’    }
113вҶ’    if (cb) {
114вҶ’      cb(client_id);
115вҶ’    }
116вҶ’  }
117вҶ’
118вҶ’  /// Invoke the connect callback registered by BridgeServer.
119вҶ’  void simulate_connect(const std::string& client_id) {
120вҶ’    ConnectionCallback cb;
121вҶ’    {
122вҶ’      std::lock_guard<std::mutex> lock(cb_mutex_);
123вҶ’      cb = on_connect_;
124вҶ’    }
125вҶ’    if (cb) {
126вҶ’      cb(client_id);
127вҶ’    }
128вҶ’  }
129вҶ’
130вҶ’  /// Get the most recent reply sent to a given client (empty json on miss).
131вҶ’  json pop_reply(const std::string& client_id) {
132вҶ’    std::lock_guard<std::mutex> lock(reply_mutex_);
133вҶ’    for (auto it = replies_.rbegin(); it != replies_.rend(); ++it) {
134вҶ’      if (it->first == client_id) {
135вҶ’        std::string text(it->second.begin(), it->second.end());
136вҶ’        json j = json::parse(text, nullptr, false);
137вҶ’        replies_.erase(std::next(it).base());
138вҶ’        return j;
139вҶ’      }
140вҶ’    }
141вҶ’    return json{};
142вҶ’  }
143вҶ’
144вҶ’  /// Return all recorded binary sends (client_id, raw bytes).
145вҶ’  std::vector<std::pair<std::string, std::vector<uint8_t>>> get_binary_sends() {
146вҶ’    std::lock_guard<std::mutex> lock(binary_mutex_);
147вҶ’    return binary_sends_;
148вҶ’  }
149вҶ’
150вҶ’  void clear_binary_sends() {
151вҶ’    std::lock_guard<std::mutex> lock(binary_mutex_);
152вҶ’    binary_sends_.clear();
153вҶ’  }
154вҶ’
155вҶ’ private:
