377вҶ’// 7. PerClientFiltering
378вҶ’//
379вҶ’// We create two sessions with different (non-existent) topic subscriptions.
380вҶ’// Because the topics don't exist in the mock, subscribe will report
381вҶ’// failures вҖ” but we can still exercise the publish_aggregated_messages path.
382вҶ’//
383вҶ’// We verify that subscribing to non-existent topics returns
384вҶ’// an error containing "failures", and that send_binary is NOT called when
385вҶ’// no messages are buffered.
386вҶ’// ---------------------------------------------------------------------------
387вҶ’TEST_F(BridgeServerTest, PerClientFiltering) {
388вҶ’  ASSERT_TRUE(server_->initialize());
389вҶ’
390вҶ’  // Create two sessions via heartbeats
391вҶ’  json hb;
392вҶ’  hb["command"] = "heartbeat";
393вҶ’  mock_->push_request("client_X", hb.dump());
394вҶ’  server_->process_requests();
395вҶ’  mock_->push_request("client_Y", hb.dump());
396вҶ’  server_->process_requests();
397вҶ’  ASSERT_EQ(server_->get_active_session_count(), 2u);
398вҶ’
399вҶ’  // Attempt subscribe for client_X to a non-existent topic
400вҶ’  json sub_x;
401вҶ’  sub_x["command"] = "subscribe";
402вҶ’  sub_x["topics"] = json::array({"/nonexistent_topic_alpha"});
403вҶ’  mock_->push_request("client_X", sub_x.dump());
404вҶ’  server_->process_requests();
405вҶ’
406вҶ’  json reply_x = mock_->pop_reply("client_X");
407вҶ’  ASSERT_FALSE(reply_x.is_discarded());
408вҶ’  // All subscriptions failed since topic doesn't exist
409вҶ’  EXPECT_TRUE(reply_x.contains("failures"));
410вҶ’  EXPECT_FALSE(reply_x["failures"].empty());
411вҶ’
412вҶ’  // Attempt subscribe for client_Y to a different non-existent topic
413вҶ’  json sub_y;
414вҶ’  sub_y["command"] = "subscribe";
415вҶ’  sub_y["topics"] = json::array({"/nonexistent_topic_beta"});
416вҶ’  mock_->push_request("client_Y", sub_y.dump());
417вҶ’  server_->process_requests();
418вҶ’
419вҶ’  json reply_y = mock_->pop_reply("client_Y");
420вҶ’  ASSERT_FALSE(reply_y.is_discarded());
421вҶ’  EXPECT_TRUE(reply_y.contains("failures"));
422вҶ’  EXPECT_FALSE(reply_y["failures"].empty());
423вҶ’
424вҶ’  // Since no real subscriptions succeeded, the message buffer is empty.
425вҶ’  // Verify that send_binary has NOT been called (no data to publish).
426вҶ’  mock_->clear_binary_sends();
427вҶ’
428вҶ’  // Call publish_aggregated_messages directly a few times
429вҶ’  for (int i = 0; i < 3; ++i) {
430вҶ’    server_->publish_aggregated_messages();
431вҶ’  }
432вҶ’
433вҶ’  auto binary_sends = mock_->get_binary_sends();
434вҶ’  // No messages were buffered, so no binary sends should have occurred
435вҶ’  EXPECT_TRUE(binary_sends.empty());
436вҶ’}
