 539вҶ’// ---------------------------------------------------------------------------
 540вҶ’// Regression: StatsNotInflatedByMultipleSessions
 541вҶ’//
 542вҶ’// The old code counted stats inside the per-client send loop:
 543вҶ’//   for (client : clients_in_group) {
 544вҶ’//     if (send_binary(client, data)) {
 545вҶ’//       total_msg_count += group_msg_count;  // BUG: counted per client
 546вҶ’//     }
 547вҶ’//   }
 548вҶ’// With N clients sharing a subscription group, stats were inflated by N.
 549вҶ’// The fix counts once per group regardless of client count.
 550вҶ’//
 551вҶ’// This test creates 3 active sessions and calls publish_aggregated_messages.
 552вҶ’// With no messages in the buffer, stats must remain (0, 0) вҖ” verifying
 553вҶ’// the counting path does not produce phantom stats with multiple sessions.
 554вҶ’// ---------------------------------------------------------------------------
 555вҶ’TEST_F(BridgeServerTest, StatsNotInflatedByMultipleSessions) {
 556вҶ’  ASSERT_TRUE(server_->initialize());
 557вҶ’
 558вҶ’  // Create 3 sessions via heartbeats
 559вҶ’  json hb;
 560вҶ’  hb["command"] = "heartbeat";
 561вҶ’  for (const auto& id : {"stats_client_1", "stats_client_2", "stats_client_3"}) {
 562вҶ’    mock_->push_request(id, hb.dump());
 563вҶ’    server_->process_requests();
 564вҶ’  }
 565вҶ’  ASSERT_EQ(server_->get_active_session_count(), 3u);
 566вҶ’
 567вҶ’  // Call publish_aggregated_messages directly multiple times
 568вҶ’  for (int i = 0; i < 4; ++i) {
 569вҶ’    server_->publish_aggregated_messages();
 570вҶ’  }
 571вҶ’
 572вҶ’  // No messages were buffered, so stats must be zero
 573вҶ’  auto [msgs, bytes] = server_->get_publish_stats();
 574вҶ’  EXPECT_EQ(msgs, 0u);
 575вҶ’  EXPECT_EQ(bytes, 0u);
 576вҶ’
 577вҶ’  // No binary sends should have occurred
 578вҶ’  EXPECT_TRUE(mock_->get_binary_sends().empty());
 579вҶ’}
