 807вҶ’// ---------------------------------------------------------------------------
 808вҶ’// SubscribeSchemaEncodingFormatStructure
 809вҶ’//
 810вҶ’// This test documents the expected schema format structure.
 811вҶ’// When a subscription succeeds, each schema should be an object with:
 812вҶ’//   - "encoding": "ros2msg"
 813вҶ’//   - "definition": <string containing the message definition>
 814вҶ’//
 815вҶ’// We verify the code path by checking response structure properties.
 816вҶ’// ---------------------------------------------------------------------------
 817вҶ’TEST_F(BridgeServerTest, SubscribeSchemaEncodingFormatStructure) {
 818вҶ’  ASSERT_TRUE(server_->initialize());
 819вҶ’
 820вҶ’  // Subscribe to multiple non-existent topics to verify format handling
 821вҶ’  json request;
 822вҶ’  request["command"] = "subscribe";
 823вҶ’  request["topics"] = json::array({"/topic_a", "/topic_b", "/topic_c"});
 824вҶ’  mock_->push_request("client_schema_2", request.dump());
 825вҶ’  server_->process_requests();
 826вҶ’
 827вҶ’  json response = mock_->pop_reply("client_schema_2");
 828вҶ’  ASSERT_FALSE(response.is_discarded());
 829вҶ’
 830вҶ’  // schemas field should be an object (may be empty if all failed)
 831вҶ’  ASSERT_TRUE(response.contains("schemas"));
 832вҶ’  EXPECT_TRUE(response["schemas"].is_object());
 833вҶ’
 834вҶ’  // If there were any successful schemas, each would have encoding and definition
 835вҶ’  // For failed subscriptions, schemas is empty, which is correct behavior
 836вҶ’  for (auto& [key, value] : response["schemas"].items()) {
 837вҶ’    // Each schema entry must be an object with encoding and definition
 838вҶ’    EXPECT_TRUE(value.is_object()) << "Schema for " << key << " should be an object";
 839вҶ’    EXPECT_TRUE(value.contains("encoding")) << "Schema for " << key << " should have encoding";
 840вҶ’    EXPECT_TRUE(value.contains("definition")) << "Schema for " << key << " should have definition";
 841вҶ’    EXPECT_EQ(value["encoding"], "ros2msg") << "Schema encoding should be ros2msg";
 842вҶ’    EXPECT_TRUE(value["definition"].is_string()) << "Schema definition should be a string";
 843вҶ’  }
 844вҶ’}
