    spdlog::error("Failed to initialize bridge server");
    return 1;
}

// Now safe
auto publish_interval =
    std::chrono::duration_cast<std::chrono::nanoseconds>(std::chrono::duration<double>(1.0 / publish_rate));
```

**Alternative**: Add an explicit check before the division: `if (publish_rate <= 0.0) { error; return 1; }`. This is redundant with `initialize()` but provides defense-in-depth. I recommend doing both: move the computation AND add a guard.

**Files to modify**:
- `/home/davide/ws_plotjuggler/src/pj_ros_bridge/ros2/src/main.cpp` -- reorder timer creation after `initialize()`
- `/home/davide/ws_plotjuggler/src/pj_ros_bridge/rti/src/main.cpp` -- reorder interval computation after `initialize()`

