The current `MockSubscriptionManager` in `test_bridge_server.cpp` (lines 206-247) uses a simple `std::set<std::string>` for `subscribed_topics_`. It does NOT track ref counts -- `subscribe()` adds to a set, `unsubscribe()` removes from it. This means it cannot detect ref-count underflow (Bug #2) or leaks (Bug #1).

**For proper regression testing of #1 and #2**, enhance the mock to use `std::unordered_map<std::string, int>` for ref counting:

```cpp
class MockSubscriptionManager : public SubscriptionManagerInterface {
 public:
  // ...
  bool subscribe(const std::string& topic_name, const std::string& /*topic_type*/) override {
    if (known_topics_.find(topic_name) == known_topics_.end()) {
      return false;
    }
    ref_counts_[topic_name]++;
    return true;
  }

  bool unsubscribe(const std::string& topic_name) override {
    auto it = ref_counts_.find(topic_name);
    if (it == ref_counts_.end() || it->second <= 0) {
      underflow_detected_ = true;
      return false;
    }
    it->second--;
    if (it->second == 0) {
      ref_counts_.erase(it);
    }
    return true;
  }

